const DEM_GRID = 36;

// ═══════════════════════════════════════════════════════════
//  FLOODSIGHT — Advanced Hydrological Simulation Engine
//  Physics: Manning's eq, SCS Curve Number, Horton infiltration,
//           Reynolds number, Froude number, hydrostatic pressure,
//           Penman-Monteith evapotranspiration
// ═══════════════════════════════════════════════════════════

// ── CURSOR ──
// Safe global readable by any early-running animation before waterLvl is declared
window._safeWL = 0; // updated every frame by loop()
// emoji cursor disabled — using default OS cursor
let mx=window.innerWidth/2, my=window.innerHeight/2;

// ── Fluid water-drop particle trail ──
const trailParticles = [];
let lastTrailX = mx, lastTrailY = my;
const trailCanvas = document.createElement('canvas');
trailCanvas.style.cssText = 'position:fixed;inset:0;pointer-events:none;z-index:9994;';
document.body.appendChild(trailCanvas);
const tctx = trailCanvas.getContext('2d');
function resizeTrail(){ trailCanvas.width=window.innerWidth; trailCanvas.height=window.innerHeight; }
resizeTrail(); window.addEventListener('resize', resizeTrail);

document.addEventListener('mousemove', e=>{
  const dx = e.clientX - lastTrailX, dy = e.clientY - lastTrailY;
  const speed = Math.sqrt(dx*dx+dy*dy);
  const isNight = document.body.classList.contains('night-mode');
  if(speed > 5){
    trailParticles.push({
      x: lastTrailX + dx*.5 + (Math.random()-.5)*2,
      y: lastTrailY + dy*.5 + (Math.random()-.5)*2,
      vx: (Math.random()-.5)*.5,
      vy: isNight ? (Math.random()-.5)*.4 : (-Math.random()*.8 - 0.2),
      r: isNight ? (1+Math.random()*2) : (1.5+Math.random()*2.5),
      life: isNight ? 0.8 : 0.55,
      decay: 0.032 + Math.random()*0.018,
      hue: isNight ? (200+Math.random()*160) : (195+Math.random()*20),
      isStar: isNight,
      starPts: Math.random() > .5 ? 4 : 5,
    });
    if(trailParticles.length > 9) trailParticles.splice(0, trailParticles.length-9);
  }
  lastTrailX=e.clientX; lastTrailY=e.clientY;
});

function drawStar(ctx, x, y, pts, r, a, hue){
  ctx.save(); ctx.globalAlpha=a;
  ctx.translate(x,y);
  ctx.beginPath();
  for(let i=0;i<pts*2;i++){
    const ang = (i*Math.PI)/pts;
    const rad = i%2===0 ? r : r*.42;
    i===0 ? ctx.moveTo(Math.cos(ang)*rad, Math.sin(ang)*rad)
           : ctx.lineTo(Math.cos(ang)*rad, Math.sin(ang)*rad);
  }
  ctx.closePath();
  const g=ctx.createRadialGradient(0,0,0,0,0,r);
  g.addColorStop(0,`hsla(${hue},90%,95%,1)`);
  g.addColorStop(0.5,`hsla(${hue},80%,75%,0.8)`);
  g.addColorStop(1,`hsla(${hue},70%,60%,0)`);
  ctx.fillStyle=g; ctx.fill();
  // Twinkle crosshair
  ctx.strokeStyle=`hsla(${hue},80%,90%,${a*.6})`; ctx.lineWidth=.5;
  ctx.beginPath(); ctx.moveTo(-r*1.5,0); ctx.lineTo(r*1.5,0); ctx.stroke();
  ctx.beginPath(); ctx.moveTo(0,-r*1.5); ctx.lineTo(0,r*1.5); ctx.stroke();
  ctx.restore();
}

(function animTrail(){
  tctx.clearRect(0,0,trailCanvas.width,trailCanvas.height);
  for(let i=trailParticles.length-1;i>=0;i--){
    const p=trailParticles[i];
    p.x+=p.vx; p.y+=p.vy;
    if(!p.isStar) p.vy+=0.06;
    p.vx*=0.96; p.life-=p.decay;
    if(p.life<=0){ trailParticles.splice(i,1); continue; }
    if(p.isStar){
      drawStar(tctx, p.x, p.y, p.starPts, p.r*2.2, p.life*0.7, p.hue);
    } else {
      const a = p.life * 0.55;
      const grd = tctx.createRadialGradient(p.x-p.r*.3,p.y-p.r*.3,p.r*.05,p.x,p.y,p.r);
      grd.addColorStop(0, `rgba(255,255,255,${a*.8})`);
      grd.addColorStop(0.4, `hsla(${p.hue},85%,80%,${a*.55})`);
      grd.addColorStop(1, `hsla(${p.hue},75%,58%,0)`);
      tctx.beginPath(); tctx.arc(p.x,p.y,p.r,0,Math.PI*2);
      tctx.fillStyle=grd; tctx.fill();
      tctx.beginPath(); tctx.arc(p.x-p.r*.3,p.y-p.r*.35,p.r*.18,0,Math.PI*2);
      tctx.fillStyle=`rgba(255,255,255,${a*.5})`; tctx.fill();
    }
  }
  requestAnimationFrame(animTrail);
})();

// ── 🌸 SAKURA PETAL RAIN ──
const sakuraCanvas = document.createElement('canvas');
sakuraCanvas.style.cssText='position:fixed;inset:0;pointer-events:none;z-index:9990;';
document.body.appendChild(sakuraCanvas);
const skctx = sakuraCanvas.getContext('2d');
function resizeSakura(){ sakuraCanvas.width=window.innerWidth; sakuraCanvas.height=window.innerHeight; }
resizeSakura(); window.addEventListener('resize', resizeSakura);

const sakuraPetals = [];
function spawnSakura(){
  // 5-petal shape via rotation
  sakuraPetals.push({
    x: Math.random() * sakuraCanvas.width,
    y: -14,
    vx: 0.6 + Math.random()*0.8,   // drift right
    vy: 0.8 + Math.random()*0.6,   // fall down
    rot: Math.random()*Math.PI*2,
    rotV: (Math.random()-0.5)*0.06,
    sway: Math.random()*Math.PI*2,  // phase for sinusoidal sway
    size: 4 + Math.random()*4,
    alpha: 0.6 + Math.random()*0.35,
    hue: 340 + Math.random()*20,
  });
}

function drawPetal(ctx, p){
  ctx.save();
  ctx.globalAlpha = p.alpha;
  ctx.translate(p.x, p.y);
  ctx.rotate(p.rot);
  // 5-petal flower
  for(let i=0;i<5;i++){
    ctx.save();
    ctx.rotate(i * Math.PI*2/5);
    ctx.beginPath();
    ctx.ellipse(0, -p.size*0.7, p.size*0.45, p.size*0.75, 0, 0, Math.PI*2);
    const g=ctx.createRadialGradient(0,-p.size*.5,0,0,-p.size*.5,p.size);
    g.addColorStop(0,`hsla(${p.hue},85%,90%,1)`);
    g.addColorStop(1,`hsla(${p.hue-10},70%,75%,0.7)`);
    ctx.fillStyle=g; ctx.fill();
    ctx.restore();
  }
  // Centre dot
  ctx.beginPath(); ctx.arc(0,0,p.size*.18,0,Math.PI*2);
  ctx.fillStyle=`hsla(${p.hue-5},70%,78%,0.9)`; ctx.fill();
  ctx.restore();
}

let sakuraSpawnTick=0;
(function animSakura(){
  skctx.clearRect(0,0,sakuraCanvas.width,sakuraCanvas.height);
  // Only show petals when flood is low (wl < 25)
  const wl = window._safeWL || 0;
  const intensity = Math.max(0, 1 - wl/22); // fade out as flood rises
  if(intensity > 0){
    sakuraSpawnTick++;
    if(sakuraSpawnTick % 60 === 0 && sakuraPetals.length < 8) spawnSakura();
    for(let i=sakuraPetals.length-1;i>=0;i--){
      const p=sakuraPetals[i];
      p.sway += 0.025;
      p.x += p.vx + Math.sin(p.sway)*0.5;
      p.y += p.vy;
      p.rot += p.rotV;
      if(p.y > sakuraCanvas.height+20 || p.x > sakuraCanvas.width+20){
        sakuraPetals.splice(i,1); continue;
      }
      const a = p.alpha * intensity;
      const pCopy = {...p, alpha:a};
      drawPetal(skctx, pCopy);
    }
  } else {
    sakuraPetals.length = 0;
  }
  requestAnimationFrame(animSakura);
})();
let kIdx=0;
document.addEventListener('click',e=>{
  kIdx=(kIdx+1)%kurEmojis.length; kur.textContent=kurEmojis[kIdx];
  const sparks=['◦','·','°','˚','∘','⊙','○'];
  for(let i=0;i<6;i++){
    const s=document.createElement('div'); s.className='sparkle';
    s.style.left=e.clientX+'px'; s.style.top=e.clientY+'px';
    s.style.animationDelay=(i*.05)+'s'; s.textContent=sparks[i%sparks.length];
    s.style.transform=`translate(${(Math.random()-.5)*55}px,${(Math.random()-.5)*55}px)`;
    document.body.appendChild(s); setTimeout(()=>s.remove(),800);
  }
  // Ripple ring + fill bloom
  const rip=document.createElement('div'); rip.className='click-ripple';
  rip.style.left=e.clientX+'px'; rip.style.top=e.clientY+'px';
  document.body.appendChild(rip); setTimeout(()=>rip.remove(),700);
  const ripFill=document.createElement('div'); ripFill.className='click-ripple-fill';
  ripFill.style.left=e.clientX+'px'; ripFill.style.top=e.clientY+'px';
  document.body.appendChild(ripFill); setTimeout(()=>ripFill.remove(),700);
  // Radar ping
  const ping=document.createElement('div'); ping.className='radar-ping';
  ping.style.left=e.clientX+'px'; ping.style.top=e.clientY+'px';
  document.body.appendChild(ping); setTimeout(()=>ping.remove(),1000);
  // Click sound
  playSnd('click');
});

// ══════════════════════════════════════════
//  SOUND ENGINE — Web Audio API
//  Rain · Waves · Wind · Alert · Click
// ══════════════════════════════════════════
let AudioCtx = null;
const sndNodes = {};  // {rain,wave,wind} → {src,gain,osc}
const sndVols  = { rain:0.4, wave:0.35, wind:0.3, alert:0.6, click:0.5 };
const sndOn    = { rain:true, wave:true, wind:true, alert:true, click:true };
let audioUnlocked = false; // tracks first user gesture
let alertPlaying = false;
let lastAlertWL  = 0;

function getAudioCtx(){
  if(!AudioCtx){ AudioCtx = new (window.AudioContext||window.webkitAudioContext)(); }
  if(AudioCtx.state==='suspended') AudioCtx.resume().then(()=>{ audioUnlocked=true; });
  else audioUnlocked = true;
  return AudioCtx;
}

// ── Make rain noise (filtered white noise) ──
function startRain(){
  if(sndNodes.rain) return;
  const ctx = getAudioCtx();
  const bufSize = ctx.sampleRate * 2;
  const buf = ctx.createBuffer(1, bufSize, ctx.sampleRate);
  const data = buf.getChannelData(0);
  for(let i=0;i<bufSize;i++) data[i] = (Math.random()*2-1);
  const src = ctx.createBufferSource(); src.buffer = buf; src.loop = true;
  const bpf = ctx.createBiquadFilter(); bpf.type='bandpass'; bpf.frequency.value=1200; bpf.Q.value=0.3;
  const hpf = ctx.createBiquadFilter(); hpf.type='highpass'; hpf.frequency.value=800;
  const gain = ctx.createGain(); gain.gain.value = sndVols.rain * 0.18;
  src.connect(bpf); bpf.connect(hpf); hpf.connect(gain); gain.connect(ctx.destination);
  src.start();
  sndNodes.rain = { src, gain };
}
function stopRain(){
  if(!sndNodes.rain) return;
  try{ sndNodes.rain.src.stop(); } catch(e){}
  delete sndNodes.rain;
}

// ── Make wave sound (low-freq oscillating noise) ──
function startWave(){
  if(sndNodes.wave) return;
  const ctx = getAudioCtx();
  const bufSize = ctx.sampleRate * 3;
  const buf = ctx.createBuffer(1, bufSize, ctx.sampleRate);
  const data = buf.getChannelData(0);
  for(let i=0;i<bufSize;i++){
    const t = i/ctx.sampleRate;
    data[i] = (Math.random()*2-1) * Math.abs(Math.sin(t*0.6)) * 0.7 + Math.sin(t*1.1+Math.sin(t*0.4)*2)*0.3;
  }
  const src = ctx.createBufferSource(); src.buffer = buf; src.loop = true;
  const lpf = ctx.createBiquadFilter(); lpf.type='lowpass'; lpf.frequency.value=400;
  const gain = ctx.createGain(); gain.gain.value = sndVols.wave * 0.22;
  src.connect(lpf); lpf.connect(gain); gain.connect(ctx.destination);
  src.start();
  // LFO for "breathing" wave motion
  const lfo = ctx.createOscillator(); lfo.frequency.value=0.25;
  const lfoGain = ctx.createGain(); lfoGain.gain.value = gain.gain.value * 0.4;
  lfo.connect(lfoGain); lfoGain.connect(gain.gain);
  lfo.start();
  sndNodes.wave = { src, gain, lfo, lfoGain };
}
function stopWave(){
  if(!sndNodes.wave) return;
  try{ sndNodes.wave.src.stop(); sndNodes.wave.lfo.stop(); } catch(e){}
  delete sndNodes.wave;
}

// ── Make wind sound (sawtooth + noise blend) ──
function startWind(){
  if(sndNodes.wind) return;
  const ctx = getAudioCtx();
  const bufSize = ctx.sampleRate * 2;
  const buf = ctx.createBuffer(1, bufSize, ctx.sampleRate);
  const data = buf.getChannelData(0);
  for(let i=0;i<bufSize;i++){
    const t=i/ctx.sampleRate;
    data[i] = (Math.random()*2-1) * (0.5 + 0.5*Math.sin(t*0.8 + Math.sin(t*0.3)*3));
  }
  const src = ctx.createBufferSource(); src.buffer = buf; src.loop = true;
  const bpf = ctx.createBiquadFilter(); bpf.type='bandpass'; bpf.frequency.value=320; bpf.Q.value=0.8;
  const gain = ctx.createGain(); gain.gain.value = sndVols.wind * 0.15;
  src.connect(bpf); bpf.connect(gain); gain.connect(ctx.destination);
  src.start();
  sndNodes.wind = { src, gain };
}
function stopWind(){
  if(!sndNodes.wind) return;
  try{ sndNodes.wind.src.stop(); } catch(e){}
  delete sndNodes.wind;
}

// ── Alert siren ──
function playAlertSnd(){
  if(!sndOn.alert) return;
  const ctx = getAudioCtx();
  const osc = ctx.createOscillator();
  const gain = ctx.createGain();
  osc.type = 'sine';
  osc.frequency.setValueAtTime(880, ctx.currentTime);
  osc.frequency.linearRampToValueAtTime(440, ctx.currentTime + 0.35);
  osc.frequency.linearRampToValueAtTime(880, ctx.currentTime + 0.7);
  gain.gain.setValueAtTime(0, ctx.currentTime);
  gain.gain.linearRampToValueAtTime(sndVols.alert * 0.3, ctx.currentTime + 0.05);
  gain.gain.linearRampToValueAtTime(0, ctx.currentTime + 0.75);
  osc.connect(gain); gain.connect(ctx.destination);
  osc.start(ctx.currentTime); osc.stop(ctx.currentTime + 0.8);
}

// ── Click bloop ──
function playSnd(type){
  if(!sndOn[type]) return;
  if(type==='click'){
    const ctx = getAudioCtx();
    const now = ctx.currentTime;
    // ── Water droplet: pluck + hollow resonance ──
    // Layer 1: bright tonal pluck (the "plink")
    const osc1 = ctx.createOscillator();
    const g1   = ctx.createGain();
    osc1.type  = 'sine';
    const baseFreq = 520 + Math.random()*160;
    osc1.frequency.setValueAtTime(baseFreq * 1.6, now);
    osc1.frequency.exponentialRampToValueAtTime(baseFreq, now + 0.03);
    osc1.frequency.exponentialRampToValueAtTime(baseFreq * 0.55, now + 0.18);
    g1.gain.setValueAtTime(0, now);
    g1.gain.linearRampToValueAtTime(sndVols.click * 0.28, now + 0.005);
    g1.gain.exponentialRampToValueAtTime(0.001, now + 0.22);
    osc1.connect(g1); g1.connect(ctx.destination);
    osc1.start(now); osc1.stop(now + 0.23);

    // Layer 2: hollow "drip" thud — low sine boom
    const osc2 = ctx.createOscillator();
    const g2   = ctx.createGain();
    osc2.type  = 'sine';
    osc2.frequency.setValueAtTime(180, now);
    osc2.frequency.exponentialRampToValueAtTime(55, now + 0.09);
    g2.gain.setValueAtTime(sndVols.click * 0.18, now);
    g2.gain.exponentialRampToValueAtTime(0.001, now + 0.10);
    osc2.connect(g2); g2.connect(ctx.destination);
    osc2.start(now); osc2.stop(now + 0.11);

    // Layer 3: tiny high sparkle (water surface break)
    const osc3 = ctx.createOscillator();
    const g3   = ctx.createGain();
    osc3.type  = 'triangle';
    osc3.frequency.setValueAtTime(2200 + Math.random()*400, now + 0.002);
    osc3.frequency.exponentialRampToValueAtTime(900, now + 0.06);
    g3.gain.setValueAtTime(sndVols.click * 0.10, now + 0.002);
    g3.gain.exponentialRampToValueAtTime(0.001, now + 0.07);
    osc3.connect(g3); g3.connect(ctx.destination);
    osc3.start(now + 0.002); osc3.stop(now + 0.08);
  }
}

// ── UI Controls ──
function toggleSoundPanel(){
  document.getElementById('sound-panel').classList.toggle('open');
}
function toggleSnd(type){
  sndOn[type] = !sndOn[type];
  const btn = document.getElementById('tog-'+type);
  btn.className = sndOn[type] ? 'snd-toggle snd-on' : 'snd-toggle snd-off';
  if(type==='rain'){ sndOn.rain ? startRain() : stopRain(); }
  if(type==='wave'){ sndOn.wave ? startWave() : stopWave(); }
  if(type==='wind'){ sndOn.wind ? startWind() : stopWind(); }
}
function setSndVol(type, val){
  sndVols[type] = parseFloat(val);
  const n = sndNodes[type];
  if(n && n.gain){
    if(type==='rain') n.gain.gain.value = val * 0.18;
    if(type==='wave') n.gain.gain.value = val * 0.22;
    if(type==='wind') n.gain.gain.value = val * 0.15;
  }
}

// ── Auto-adjust ambient sounds based on simulation ──
function updateAmbientSounds(wl, rr, ws){
  if(!audioUnlocked) return; // wait for first user gesture

  // Rain: plays when rainfall > 10
  if(rr > 10 && !sndNodes.rain && sndOn.rain) startRain();
  if(rr <= 10 && sndNodes.rain) stopRain();
  if(sndNodes.rain) sndNodes.rain.gain.gain.value = sndVols.rain * 0.18 * Math.min(1, rr/40);

  // Waves: plays when water level > 15
  if(wl > 15 && !sndNodes.wave && sndOn.wave) startWave();
  if(wl <= 15 && sndNodes.wave) stopWave();
  if(sndNodes.wave) sndNodes.wave.gain.gain.value = sndVols.wave * 0.22 * Math.min(1, wl/60);

  // Wind: plays when wind > 20
  if(ws > 20 && !sndNodes.wind && sndOn.wind) startWind();
  if(ws <= 20 && sndNodes.wind) stopWind();
  if(sndNodes.wind) sndNodes.wind.gain.gain.value = sndVols.wind * 0.15 * Math.min(1, ws/60);

  // Alert sound trigger (once when crossing 78)
  if(wl > 78 && lastAlertWL <= 78 && sndOn.alert) playAlertSnd();
  lastAlertWL = wl;
}

