// ── CLOCK + SKY ICON ──
function tick(){
  const n=new Date();
  const h=n.getHours();
  const skyEl=document.getElementById('sky-icon');
  if(skyEl){
    if(h>=6&&h<8)        skyEl.textContent='🌅';
    else if(h>=8&&h<18)  skyEl.textContent='☀️';
    else if(h>=18&&h<20) skyEl.textContent='🌇';
    else if(h>=20||h<4)  skyEl.textContent='🌙';
    else                  skyEl.textContent='⭐';
    // night glow
    skyEl.style.filter = (h>=20||h<6) ? 'drop-shadow(0 0 8px rgba(180,180,255,.8))' : 'drop-shadow(0 0 6px rgba(255,200,60,.6))';
  }
  const t=n.toLocaleTimeString('en-US',{hour:'2-digit',minute:'2-digit',second:'2-digit',hour12:false});
  const htEl=document.getElementById('htime');
  if(htEl){ htEl.innerHTML=`<span id="sky-icon" style="${skyEl?skyEl.getAttribute('style'):''}">${skyEl?skyEl.textContent:'☀️'}</span>${t}`; }
  document.getElementById('hdate').textContent=n.toLocaleDateString('en-US',{weekday:'short',month:'short',day:'numeric',year:'numeric'});
}
setInterval(tick,1000); tick();

// ══════════════════════════════════════════════
// HEADER WAVE CANVAS
// ══════════════════════════════════════════════
function animateHeaderWave(){
  const cv=document.getElementById('header-wave');
  if(!cv) return;
  const ctx=cv.getContext('2d');
  let t=0;
  function draw(){
    const W=cv.width, H=cv.height;
    ctx.clearRect(0,0,W,H);
    // gradient wave fill
    const grd=ctx.createLinearGradient(0,0,W,0);
    grd.addColorStop(0,'rgba(109,200,232,0)');
    grd.addColorStop(0.2,'rgba(109,200,232,0.55)');
    grd.addColorStop(0.5,'rgba(201,184,255,0.5)');
    grd.addColorStop(0.8,'rgba(255,183,197,0.45)');
    grd.addColorStop(1,'rgba(109,200,232,0)');
    ctx.beginPath();
    ctx.moveTo(0,H);
    for(let x=0;x<=W;x+=2){
      const y = H/2 + Math.sin((x/W)*Math.PI*4 + t)*3.5 + Math.sin((x/W)*Math.PI*7 + t*1.3)*1.8;
      ctx.lineTo(x,y);
    }
    ctx.lineTo(W,H); ctx.closePath();
    ctx.fillStyle=grd; ctx.fill();
    // second wave layer
    const grd2=ctx.createLinearGradient(0,0,W,0);
    grd2.addColorStop(0,'rgba(109,200,232,0)');
    grd2.addColorStop(0.3,'rgba(109,200,232,0.28)');
    grd2.addColorStop(0.7,'rgba(201,184,255,0.22)');
    grd2.addColorStop(1,'rgba(109,200,232,0)');
    ctx.beginPath(); ctx.moveTo(0,H);
    for(let x=0;x<=W;x+=2){
      const y = H/2 + Math.sin((x/W)*Math.PI*5 + t*1.7 + 1)*2.5 + Math.sin((x/W)*Math.PI*3 + t*0.8)*2;
      ctx.lineTo(x,y);
    }
    ctx.lineTo(W,H); ctx.closePath();
    ctx.fillStyle=grd2; ctx.fill();
    t+=0.025;
    requestAnimationFrame(draw);
  }
  draw();
}
animateHeaderWave();

