// ── KAWAII CLICK SOUND on drop icon ──
function kawaiiDropClick(){
  try {
    const ctx = new (window.AudioContext||window.webkitAudioContext)();
    // Cute ascending "boing" sound
    const notes = [523, 659, 784, 1047]; // C5 E5 G5 C6
    notes.forEach((freq, i) => {
      const osc = ctx.createOscillator();
      const gain = ctx.createGain();
      osc.connect(gain); gain.connect(ctx.destination);
      osc.type = 'sine';
      osc.frequency.setValueAtTime(freq, ctx.currentTime + i*0.08);
      osc.frequency.exponentialRampToValueAtTime(freq*1.05, ctx.currentTime + i*0.08 + 0.1);
      gain.gain.setValueAtTime(0, ctx.currentTime + i*0.08);
      gain.gain.linearRampToValueAtTime(0.18, ctx.currentTime + i*0.08 + 0.02);
      gain.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + i*0.08 + 0.18);
      osc.start(ctx.currentTime + i*0.08);
      osc.stop(ctx.currentTime + i*0.08 + 0.2);
    });
    // Extra sparkle high note
    const osc2 = ctx.createOscillator();
    const gain2 = ctx.createGain();
    osc2.connect(gain2); gain2.connect(ctx.destination);
    osc2.type = 'triangle';
    osc2.frequency.setValueAtTime(2093, ctx.currentTime + 0.32);
    gain2.gain.setValueAtTime(0.12, ctx.currentTime + 0.32);
    gain2.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 0.55);
    osc2.start(ctx.currentTime + 0.32);
    osc2.stop(ctx.currentTime + 0.6);
  } catch(e){}
  // Also do a surprised expression
  setDropExpression('surprised');
  setTimeout(()=>setDropExpression('happy'), 600);
  // Spawn sparkles
  for(let i=0;i<6;i++){
    setTimeout(()=>{
      const badge=document.getElementById('logo-badge-btn');
      if(!badge) return;
      const r=badge.getBoundingClientRect();
      const sp=document.createElement('div');
      sp.className='sparkle';
      sp.textContent=['✨','💧','⭐','🌟','💫'][Math.floor(Math.random()*5)];
      sp.style.left=(r.left+r.width/2+Math.random()*40-20)+'px';
      sp.style.top=(r.top+r.height/2+Math.random()*30-15)+'px';
      document.body.appendChild(sp);
      setTimeout(()=>sp.remove(),800);
    }, i*60);
  }
}

function movePupils(dx,dy){
  const eyes=getEyes();
  eyes.forEach(e=>{
    if(!e) return;
    const after = e.querySelector('::after');
    // Use CSS custom property to shift the pupil (::after is relative, shift via JS)
    e.style.setProperty('--px', (dx*3)+'px');
    e.style.setProperty('--py', (dy*3)+'px');
    // We update via the ::after pseudo but can't directly — use data attribute approach
    e.dataset.dx = dx; e.dataset.dy = dy;
    // Shift using background on the ::after equivalent — use inline child if needed
    // Since we use ::after for pupil, shift by updating a CSS var on element
    e.style.backgroundPosition = `${50+dx*15}% ${50+dy*12}%`;
  });
}

function setEyeState(state){
  const eyeWrap=document.querySelector('.eye-wrap');
  if(!eyeWrap) return;
  const [eL,eR]=getEyes();
  // remove tears
  eyeWrap.querySelectorAll('.tear').forEach(t=>t.remove());
  eyeWrap.classList.remove('eye-scanning','eye-crying');

  if(state==='scanning'){
    eyeState='scanning';
    eyeWrap.classList.add('eye-scanning');
    let sx=-1;
    eyeScanTimer=setInterval(()=>{
      sx=-sx; movePupils(sx,0);
    }, 400);
  } else if(state==='crying'){
    eyeState='crying';
    eyeWrap.classList.add('eye-crying');
    clearInterval(eyeScanTimer);
    // Add tear drops
    [eL,eR].forEach(e=>{
      if(!e) return;
      const t=document.createElement('div'); t.className='tear';
      e.style.position='relative'; e.style.overflow='visible';
      e.appendChild(t);
    });
    movePupils(0,0.3); // look down sadly
  } else {
    eyeState='normal';
    clearInterval(eyeScanTimer);
    movePupils(0,0);
  }
}

// React to flood level changes
function updateEyeReaction(waterLevel){
  if(waterLevel>75) setEyeState('crying');
  else if(waterLevel>0 && (autoRun||typhMode)) setEyeState('scanning');
  else setEyeState('normal');
}

