// HEADER WEATHER PARTICLES
// ══════════════════════════════════════════════
let hdrParticles=[];
let hdrRainActive=false, hdrStormActive=false;
let hdrLightningTimer=null;

function clearHeaderParticles(){
  const p=document.getElementById('header-particles');
  if(p){ p.innerHTML=''; }
  clearInterval(hdrLightningTimer); hdrLightningTimer=null;
  hdrRainActive=false; hdrStormActive=false;
}

function startHeaderRain(intense){
  clearHeaderParticles();
  hdrRainActive=true;
  const p=document.getElementById('header-particles');
  if(!p) return;
  const count=intense?42:16;
  for(let i=0;i<count;i++){
    const d=document.createElement('div');
    d.className='hdr-rain'+(intense?' heavy':'');
    const h=intense?(8+Math.random()*16):(5+Math.random()*10);
    const w=intense?(1.5+Math.random()):(1+Math.random()*.5);
    const spd=intense?(0.3+Math.random()*0.35):(0.45+Math.random()*0.5);
    d.style.cssText=`left:${Math.random()*108-4}%;top:${-h}px;height:${h}px;width:${w}px;opacity:${0.5+Math.random()*.4};animation-name:${intense?'hdrRainHeavy':'hdrRainFall'};animation-duration:${spd}s;animation-delay:${-Math.random()*1.5}s;`;
    p.appendChild(d);
  }
  if(intense){
    hdrStormActive=true;
    // Wind streaks
    for(let i=0;i<5;i++){
      const w=document.createElement('div'); w.className='hdr-wind';
      w.style.cssText=`top:${15+Math.random()*70}%;width:${60+Math.random()*120}px;animation-duration:${1.2+Math.random()*1}s;animation-delay:${-Math.random()*2}s;left:0;`;
      p.appendChild(w);
    }
    // Lightning flash + bolt periodically
    hdrLightningTimer=setInterval(()=>{
      if(!hdrStormActive) return;
      // Flash overlay
      const fl=document.createElement('div'); fl.className='hdr-lightning flash';
      p.appendChild(fl);
      setTimeout(()=>fl.remove(), 300);
      // Lightning bolt emoji at random position
      setTimeout(()=>{
        const bolt=document.createElement('div'); bolt.className='hdr-bolt';
        bolt.textContent='⚡';
        bolt.style.left=(10+Math.random()*80)+'%';
        bolt.style.top=(10+Math.random()*60)+'%';
        p.appendChild(bolt);
        setTimeout(()=>bolt.remove(), 400);
      }, 60);
    }, 1800+Math.random()*2500);
  }
}

function updateHeaderWeather(rainRate, windSpd, isTyphoon){
  if(isTyphoon || (rainRate>40&&windSpd>40)){
    if(!hdrStormActive) startHeaderRain(true);
  } else if(rainRate>10){
    if(!hdrRainActive||hdrStormActive){ startHeaderRain(false); }
  } else {
    if(hdrRainActive||hdrStormActive) clearHeaderParticles();
  }
}

