// ── CANVAS FISH — full body-wave swimming ──
(function initFishCanvas(){
  const fc = document.getElementById('tank-fish-cv');
  if(!fc) return;
  const fctx = fc.getContext('2d');
  const FW = 38, FH = 22;
  let fishT = 0;

  function drawFish(t, stressed){
    fctx.clearRect(0,0,FW,FH);
    const cx = FW*0.52, cy = FH*0.5;
    const bodyColor = stressed ? '#f07090' : '#4ab8e8';
    const darkColor  = stressed ? '#c04060' : '#2a88c0';
    const finColor   = stressed ? 'rgba(255,130,160,.7)' : 'rgba(100,200,240,.75)';

    // ── Body wave: S-curve via spine points ──
    const spineLen = 22;
    const freq = 2.8, amp = 3.5, speed = t * 3.8;
    const spine = [];
    for(let i=0;i<=12;i++){
      const frac = i/12;
      const x = cx - spineLen*0.5 + frac*spineLen;
      // Wave amplitude increases toward tail
      const wave = Math.sin(freq*frac*Math.PI - speed) * amp * frac;
      spine.push({x, y: cy + wave});
    }

    // Draw body using perpendicular thickness along spine
    const bodyThickness = (frac)=> 5.5 * Math.sin(frac * Math.PI) * (1 - frac*.3);
    fctx.save();
    // Top edge
    fctx.beginPath();
    spine.forEach(({x,y},i)=>{
      const thick = bodyThickness(i/spine.length);
      i===0 ? fctx.moveTo(x, y-thick) : fctx.lineTo(x, y-thick);
    });
    // Bottom edge (reverse)
    for(let i=spine.length-1;i>=0;i--){
      const {x,y}=spine[i];
      const thick = bodyThickness(i/spine.length);
      fctx.lineTo(x, y+thick);
    }
    fctx.closePath();
    const bg = fctx.createLinearGradient(cx-11,cy-5,cx-11,cy+5);
    bg.addColorStop(0,'rgba(255,255,255,.65)');
    bg.addColorStop(0.4,bodyColor);
    bg.addColorStop(1,darkColor);
    fctx.fillStyle=bg; fctx.fill();
    fctx.strokeStyle='rgba(0,0,0,.07)'; fctx.lineWidth=.5; fctx.stroke();
    fctx.restore();

    // Tail — fan at tail end of spine
    const tail = spine[spine.length-1];
    const tailWave = Math.sin(speed + Math.PI)*1.8;
    fctx.save();
    fctx.fillStyle=finColor;
    fctx.beginPath();
    fctx.moveTo(tail.x, tail.y);
    fctx.quadraticCurveTo(tail.x+5, tail.y+tailWave+5, tail.x+9, tail.y+tailWave+3);
    fctx.quadraticCurveTo(tail.x+7, tail.y+tailWave, tail.x+9, tail.y+tailWave-3);
    fctx.quadraticCurveTo(tail.x+5, tail.y+tailWave-5, tail.x, tail.y);
    fctx.closePath(); fctx.fill();
    fctx.restore();

    // Dorsal fin — waves with body
    const mid = spine[5];
    const dorsalWave = Math.sin(speed)*1.2;
    fctx.save();
    fctx.fillStyle=finColor;
    fctx.beginPath();
    fctx.moveTo(mid.x-3, mid.y-4);
    fctx.quadraticCurveTo(mid.x+1, mid.y-9+dorsalWave, mid.x+5, mid.y-4);
    fctx.lineTo(mid.x-3, mid.y-4); fctx.closePath(); fctx.fill();
    fctx.restore();

    // Pectoral fin
    const pect = spine[3];
    fctx.save();
    fctx.fillStyle=finColor;
    fctx.beginPath();
    fctx.moveTo(pect.x, pect.y+2);
    fctx.quadraticCurveTo(pect.x-1, pect.y+7+Math.sin(speed*.7)*1.5, pect.x+5, pect.y+5);
    fctx.closePath(); fctx.fill();
    fctx.restore();

    // Eye
    const eye = spine[1];
    fctx.save();
    fctx.fillStyle='#fff'; fctx.beginPath(); fctx.arc(eye.x+1, eye.y-1, 2.5, 0, Math.PI*2); fctx.fill();
    fctx.fillStyle='#1a4060'; fctx.beginPath(); fctx.arc(eye.x+1.5, eye.y-1, 1.4, 0, Math.PI*2); fctx.fill();
    fctx.fillStyle='rgba(255,255,255,.85)'; fctx.beginPath(); fctx.arc(eye.x+2, eye.y-1.8, .55, 0, Math.PI*2); fctx.fill();
    fctx.restore();

    fishT += 0.028;
  }

  function loopFish(){
    const wl = parseFloat(document.getElementById('s-wl')?.value)||0;
    drawFish(fishT, wl>70);
    requestAnimationFrame(loopFish);
  }
  loopFish();
})();

// ── CANVAS FISH 2 — small companion (orange clownfish) ──
(function initFish2(){
  const fc2 = document.getElementById('tank-fish2-cv');
  if(!fc2) return;
  const f2ctx = fc2.getContext('2d');
  const FW=26, FH=16;
  let fishT2=1.5; // offset phase

  function drawFish2(t){
    f2ctx.clearRect(0,0,FW,FH);
    const cx=FW*.52, cy=FH*.5;
    const spineLen=16, freq=3.2, amp=2.8, speed=t*4.5;
    const spine=[];
    for(let i=0;i<=10;i++){
      const frac=i/10;
      spine.push({
        x: cx-spineLen*.5+frac*spineLen,
        y: cy+Math.sin(freq*frac*Math.PI-speed)*amp*frac
      });
    }
    const thick=(frac)=>4*Math.sin(frac*Math.PI)*(1-frac*.3);
    // Body
    f2ctx.save();
    f2ctx.beginPath();
    spine.forEach(({x,y},i)=>{ const t2=thick(i/spine.length); i===0?f2ctx.moveTo(x,y-t2):f2ctx.lineTo(x,y-t2); });
    for(let i=spine.length-1;i>=0;i--){ const {x,y}=spine[i]; f2ctx.lineTo(x,y+thick(i/spine.length)); }
    f2ctx.closePath();
    const bg=f2ctx.createLinearGradient(cx-8,cy-4,cx-8,cy+4);
    bg.addColorStop(0,'rgba(255,255,255,.6)'); bg.addColorStop(.4,'#ff8c38'); bg.addColorStop(1,'#c05010');
    f2ctx.fillStyle=bg; f2ctx.fill();
    // White stripes
    [0.25,0.55].forEach(sf=>{
      const si=Math.floor(sf*spine.length);
      if(si>=spine.length) return;
      const {x,y}=spine[si]; const tk=thick(sf)*1.1;
      f2ctx.strokeStyle='rgba(255,255,255,.85)'; f2ctx.lineWidth=1.8; f2ctx.lineCap='round';
      f2ctx.beginPath(); f2ctx.moveTo(x,y-tk); f2ctx.lineTo(x,y+tk); f2ctx.stroke();
    });
    f2ctx.restore();
    // Tail
    const tail=spine[spine.length-1];
    const tw3=Math.sin(speed+Math.PI)*1.5;
    f2ctx.save(); f2ctx.fillStyle='rgba(255,120,30,.8)';
    f2ctx.beginPath(); f2ctx.moveTo(tail.x,tail.y);
    f2ctx.quadraticCurveTo(tail.x+4,tail.y+tw3+3.5,tail.x+7,tail.y+tw3+2);
    f2ctx.quadraticCurveTo(tail.x+5,tail.y+tw3,tail.x+7,tail.y+tw3-2);
    f2ctx.quadraticCurveTo(tail.x+4,tail.y+tw3-3.5,tail.x,tail.y);
    f2ctx.closePath(); f2ctx.fill(); f2ctx.restore();
    // Eye
    const ey2=spine[1]; f2ctx.save();
    f2ctx.fillStyle='#fff'; f2ctx.beginPath(); f2ctx.arc(ey2.x+.5,ey2.y-.8,1.8,0,Math.PI*2); f2ctx.fill();
    f2ctx.fillStyle='#1a3020'; f2ctx.beginPath(); f2ctx.arc(ey2.x+.8,ey2.y-.8,1,0,Math.PI*2); f2ctx.fill();
    f2ctx.restore();
    fishT2+=0.032;
  }
  function loopFish2(){ drawFish2(fishT2); requestAnimationFrame(loopFish2); }
  loopFish2();
})();

