// ── MASCOT ──
const mctx=document.getElementById('mascot-cv').getContext('2d');
document.getElementById('mascot-cv').width=88; document.getElementById('mascot-cv').height=88;
let mt=0,blinkT=0,tailT=0;
let sukiIdleTimer=null, sukiIdleMode=null, sukiSpinAngle=0, sukiSpinActive=false;

function resetSukiIdle(){
  clearTimeout(sukiIdleTimer);
  sukiIdleMode=null; sukiSpinActive=false; sukiSpinAngle=0;
  sukiIdleTimer=setTimeout(()=>{
    sukiIdleMode = Math.random()>.5 ? 'spin' : 'happy3';
    if(sukiIdleMode==='spin') sukiSpinActive=true;
    // return to normal after 4s
    setTimeout(()=>{ sukiIdleMode=null; sukiSpinActive=false; sukiSpinAngle=0; resetSukiIdle(); }, 4000);
  }, 30000);
}
// Reset idle on any slider/button interaction
document.addEventListener('input', resetSukiIdle);
document.addEventListener('click', resetSukiIdle);
resetSukiIdle();
function drawSuki(wl){
  const W=88,H=88;
  mctx.clearRect(0,0,W,H);
  mctx.save();

  // ── Spin idle: rotate whole fish around canvas centre ──
  if(sukiSpinActive){
    sukiSpinAngle += 0.09;
    mctx.translate(W/2,H/2);
    mctx.rotate(sukiSpinAngle);
    mctx.translate(-W/2,-H/2);
    // Sparkles during spin
    for(let i=0;i<4;i++){
      const sa=sukiSpinAngle*2+i*(Math.PI/2);
      const sx=W/2+32*Math.cos(sa), sy=H/2+24*Math.sin(sa);
      mctx.fillStyle=`hsla(${(i*60+sukiSpinAngle*80)%360},90%,75%,.7)`;
      mctx.font='9px serif'; mctx.textAlign='center'; mctx.fillText('✦',sx,sy);
    }
  }

  const cx=44, cy=44+Math.sin(mt*2.2)*3.5;
  // Halo
  const halo=mctx.createRadialGradient(cx,cy,4,cx,cy,34);
  halo.addColorStop(0,wl>70?'rgba(255,130,160,0.22)':'rgba(109,200,232,0.22)'); halo.addColorStop(1,'transparent');
  mctx.fillStyle=halo; mctx.beginPath(); mctx.arc(cx,cy,34,0,Math.PI*2); mctx.fill();
  // Body
  const bc=wl>70?'#ff9eb5':wl>40?'#ffb3c6':'#7dd8f0';
  const bg2=mctx.createRadialGradient(cx-5,cy-7,2,cx,cy,19);
  bg2.addColorStop(0,'rgba(255,255,255,.6)'); bg2.addColorStop(.5,bc); bg2.addColorStop(1,wl>70?'#e87090':'#3a9bbf');
  mctx.fillStyle=bg2; mctx.beginPath(); mctx.ellipse(cx+2,cy,20,15,0,0,Math.PI*2); mctx.fill();
  // Blush
  mctx.fillStyle='rgba(255,150,180,.32)';
  mctx.beginPath(); mctx.ellipse(cx+12,cy+4,5,3.5,.3,0,Math.PI*2); mctx.fill();
  mctx.beginPath(); mctx.ellipse(cx-1,cy+5,4,3,.3,0,Math.PI*2); mctx.fill();
  // Tail
  const tw2=Math.sin(tailT*4)*.38;
  mctx.fillStyle=wl>70?'#ff7090':'#43b8d8';
  mctx.beginPath(); mctx.moveTo(cx-16,cy);
  mctx.quadraticCurveTo(cx-27,cy+tw2*12,cx-23,cy+12+tw2*8);
  mctx.quadraticCurveTo(cx-29,cy+tw2*6,cx-23,cy-10+tw2*8); mctx.closePath(); mctx.fill();
  // Fin
  mctx.fillStyle='rgba(109,200,232,.7)';
  mctx.beginPath(); mctx.moveTo(cx+2,cy-13);
  mctx.quadraticCurveTo(cx+8,cy-23+Math.sin(mt*3)*2,cx+16,cy-10); mctx.lineTo(cx+2,cy-13); mctx.fill();

  // ── Face — normal or :3 idle ──
  const ex=cx+10, ey=cy-4;
  if(sukiIdleMode==='happy3'){
    // :3 face — cat-like squint + cute mouth
    mctx.strokeStyle='#fff'; mctx.lineWidth=2.2; mctx.lineCap='round';
    mctx.beginPath(); mctx.moveTo(ex-3.5,ey+.5); mctx.quadraticCurveTo(ex,ey-2.5,ex+3.5,ey+.5); mctx.stroke();
    // :3 mouth
    mctx.strokeStyle='rgba(255,150,200,.9)'; mctx.lineWidth=1.8;
    mctx.beginPath(); mctx.moveTo(cx+3,cy+5); mctx.quadraticCurveTo(cx+7,cy+9,cx+13,cy+5); mctx.stroke();
    // Rosy blush boost
    mctx.fillStyle='rgba(255,130,180,.38)';
    mctx.beginPath(); mctx.ellipse(cx+14,cy+3,6,4,.3,0,Math.PI*2); mctx.fill();
  } else {
    const blink=Math.sin(blinkT)>.93;
    if(blink){ mctx.strokeStyle='#fff'; mctx.lineWidth=2.5; mctx.lineCap='round'; mctx.beginPath(); mctx.moveTo(ex-4,ey); mctx.lineTo(ex+4,ey); mctx.stroke(); }
    else {
      mctx.fillStyle='#fff'; mctx.beginPath(); mctx.ellipse(ex,ey,5.5,5.5,0,0,Math.PI*2); mctx.fill();
      mctx.fillStyle=wl>70?'#c0304a':'#1a5c8a'; mctx.beginPath(); mctx.ellipse(ex+1,ey+.5,3,3,0,0,Math.PI*2); mctx.fill();
      mctx.fillStyle='#fff'; mctx.beginPath(); mctx.ellipse(ex+2,ey-1,1.2,1.2,0,0,Math.PI*2); mctx.fill();
    }
  }

  // Orbiting particles
  const orbitSyms=wl>70?['!','⚡','⚠','!']:wl>20?['~','…','?','~']:['◦','·','°','˚'];
  for(let i=0;i<3;i++){
    const sa=mt*1.4+i*(Math.PI*2/3), sx=cx+30*Math.cos(sa), sy=cy+22*Math.sin(sa);
    mctx.fillStyle=wl>70?'rgba(255,100,120,.65)':wl>20?'rgba(255,200,100,.6)':'rgba(109,200,232,.6)';
    mctx.font='10px serif'; mctx.textAlign='center'; mctx.fillText(orbitSyms[i],sx,sy);
  }
  mctx.restore();
  mt+=.03; blinkT+=.033; tailT+=.04;
}
function setMascotMsg(wl,rr,ws){
  const el=document.getElementById('mascot-bubble');
  if(wl>78) el.textContent='Critical flood detected! Please evacuate immediately! ⚠️';
  else if(wl>55) el.textContent='Water is very high! This is dangerous! Stay alert! 🌊';
  else if(wl>28) el.textContent='Flood risk rising~ please monitor closely! 👀';
  else if(rr>60) el.textContent='Heavy rain detected! Watch those rivers! 🌧️';
  else if(ws>60) el.textContent='Strong winds! Could worsen flooding risk! 💨';
  else if(wl>5) el.textContent='Slight water rise detected. Staying watchful~ 🔍';
  else el.textContent='Hi there~ Water levels are normal! Stay safe! ✦';
}

// ══════════════════════════════════════════
//  REAL DEM TERRAIN ENGINE — SRTM 30m data
//  36×36 real city grids, bilinear upsampled to 72×72
// ══════════════════════════════════════════
const GRID=72; let heights=[], currentDEMKey='tainan';

// Bilinear interpolation from 36×36 → 72×72
function buildHeightmap(demKey){
  const src = REAL_DEM[demKey].grid;  // 36×36 = 1296 values (metres)
  const maxE = src.reduce((a,b)=>a>b?a:b,0);
  heights = [];
  for(let r=0;r<=GRID;r++) for(let c=0;c<=GRID;c++){
    // Map 72×72 → 36×36
    const sr = r/GRID*(DEM_GRID-1), sc2 = c/GRID*(DEM_GRID-1);
    const r0=Math.floor(sr), c0=Math.floor(sc2);
    const r1=Math.min(DEM_GRID-1,r0+1), c1=Math.min(DEM_GRID-1,c0+1);
    const fr=sr-r0, fc=sc2-c0;
    const idx=(rr,cc)=>rr*DEM_GRID+cc;
    const v00=src[idx(r0,c0)], v10=src[idx(r1,c0)];
    const v01=src[idx(r0,c1)], v11=src[idx(r1,c1)];
    const v = v00*(1-fr)*(1-fc) + v10*fr*(1-fc) + v01*(1-fr)*fc + v11*fr*fc;
    heights.push(v / maxE); // normalise 0→1
  }
  // Update city info chips
  const city = REAL_DEM[demKey];
  const src2 = city.grid;
  const minE=Math.min(...src2), avgE=Math.round(src2.reduce((a,b)=>a+b,0)/src2.length);
  document.getElementById('chip-elev-min').textContent = minE.toFixed(0)+'m';
  const maxE2=src2.reduce((a,b)=>a>b?a:b,0); document.getElementById('chip-elev-max').textContent = maxE2.toFixed(0)+'m';
  document.getElementById('chip-elev-avg').textContent = avgE+'m';
  // Show toast
  showDEMToast(city.name, minE.toFixed(0), maxE2.toFixed(0));
}

function showDEMToast(cityName, minE, maxE){
  const t=document.getElementById('dem-toast');
  const txt=document.getElementById('dem-toast-txt');
  if(!t||!txt) return;
  txt.textContent = `Real SRTM loaded: ${cityName} · ${minE}m – ${maxE}m`;
  // Reset animation
  const fill=t.querySelector('.dem-fill');
  if(fill){ fill.style.animation='none'; fill.offsetHeight; fill.style.animation=''; }
  t.classList.add('show');
  setTimeout(()=>t.classList.remove('show'), 2800);
}

function genTerrain(seed){
  // seed ignored — we use real DEM. Kept for API compat.
  buildHeightmap(currentDEMKey);
}
// genTerrain called after canvas init below
function gh(r,c){ return heights[Math.max(0,Math.min(GRID,r))*(GRID+1)+Math.max(0,Math.min(GRID,c))]||0; }

function terrCol(h,wn){
  // h is normalised 0-1 relative to city max elevation
  if(h<wn-.01){
    const d=Math.min(1,(wn-h)*7);
    return `rgba(${Math.round(45+d*30)},${Math.round(130+d*25)},${Math.round(200+d*30)},1)`;
  }
  if(h<wn+.012) return '#b8e8f8'; // waterline shore
  if(h<.03)  return '#e8f4d0'; // sea-level mudflat / tidal
  if(h<.08)  return '#d0e8a0'; // lowland rice fields (Tainan basin)
  if(h<.18)  return '#b8d878'; // low hills
  if(h<.32)  return '#90c058'; // mid elevation forest
  if(h<.50)  return '#689040'; // mountain forest
  if(h<.65)  return '#a09060'; // rocky highland
  if(h<.80)  return '#c8b890'; // bare rock
  return '#ece8e0';             // snow/peaks (Taroko, Yushan area)
}

// ── SIM CANVAS ──
const sc=document.getElementById('sim-canvas'), sctx=sc.getContext('2d');
let simW=0,simH=0;
function resizeSim(){
  const el = document.getElementById('center');
  if (!el) return;
  const r = el.getBoundingClientRect();
  const W = r.width  || el.offsetWidth  || el.clientWidth  || 800;
  const H = r.height || el.offsetHeight || el.clientHeight || 580;
  if(W < 10 || H < 10) { simW=sc.width=800; simH=sc.height=580; return; }
  simW=sc.width=W; simH=sc.height=H;
}
// Don't call resizeSim here — called in init sequence below
// Hoist typhoon state so resize listener can safely reference it
let selectedTyphoon = null;
let replayStep = 0;
let replayPlaying = false;
let replayInterval = null;
let replaySpeed = 1;

window.addEventListener('resize',()=>{
  resizeSim();
  if(selectedTyphoon) buildTrackOverlay(selectedTyphoon);
});

let waterLvl=0,waveTime=0,waveInt=0.3,rainR=0,windSpd=0,viewAng=45,tempC=28,saturation=40;
let autoRun=false,typhMode=false;
let drops=[],bubbles=[];
let displayWL=0; // smooth lerped water level for 3D
let surfaceRipples=[]; // water surface ripple rings

function isoP(wx,wy,wz,ang){
  const a=ang*Math.PI/180,sn=Math.sin(a),cw=simW/(GRID*1.4),ch=cw*.5;
  return{x:simW/2+(wx-wy)*cw, y:simH*.34+(wx+wy)*ch*sn-wz*cw*.85};
}

function renderSim(){
  // Smooth water level lerp (7% per frame)
  displayWL += (waterLvl - displayWL) * 0.07;
  const smoothWn = displayWL / 100;

  sctx.clearRect(0,0,simW,simH);
  // Pastel sky
  const sky=sctx.createLinearGradient(0,0,0,simH);
  sky.addColorStop(0,'#eaf5ff'); sky.addColorStop(.5,'#f0eeff'); sky.addColorStop(1,'#eafff5');
  sctx.fillStyle=sky; sctx.fillRect(0,0,simW,simH);
  // Soft clouds
  [[simW*.18,simH*.1,55],[simW*.55,simH*.08,72],[simW*.82,simH*.13,45]].forEach(([cx,cy,sz])=>{
    const cg=sctx.createRadialGradient(cx,cy,4,cx,cy,sz);
    cg.addColorStop(0,'rgba(255,255,255,.52)'); cg.addColorStop(1,'transparent');
    sctx.fillStyle=cg; sctx.beginPath(); sctx.ellipse(cx,cy,sz,sz*.48,0,0,Math.PI*2); sctx.fill();
  });

  const wn=smoothWn;

  // Rain
  if(rainR>0) for(let i=0;i<Math.floor(rainR/5);i++) drops.push({x:Math.random()*simW,y:Math.random()*simH*.58,vy:5+Math.random()*4.5,vx:-(windSpd/100)*.8-.3,life:1});
  drops=drops.filter(d=>d.life>0); bubbles=bubbles.filter(b=>b.life>0);
  drops.forEach(d=>{d.x+=d.vx;d.y+=d.vy;d.life-=.028;});
  bubbles.forEach(b=>{b.x+=b.vx;b.y+=b.vy;b.life-=.013;});

  // Terrain
  for(let r=GRID-1;r>=0;r--){
    for(let c=0;c<GRID;c++){
      const h00=gh(r,c),h10=gh(r+1,c),h01=gh(r,c+1),h11=gh(r+1,c+1);
      const wo=waveInt*.018*(Math.sin(waveTime*2+r*.35+c*.45)+Math.cos(waveTime*1.6+r*.55-c*.22)*.45);
      const p00=isoP(c,r,h00*2.65,viewAng),p10=isoP(c,r+1,h10*2.65,viewAng);
      const p01=isoP(c+1,r,h01*2.65,viewAng),p11=isoP(c+1,r+1,h11*2.65,viewAng);
      const avg=(h00+h10+h01+h11)/4;
      sctx.fillStyle=terrCol(avg,wn);
      sctx.beginPath(); sctx.moveTo(p00.x,p00.y); sctx.lineTo(p01.x,p01.y);
      sctx.lineTo(p11.x,p11.y); sctx.lineTo(p10.x,p10.y); sctx.closePath(); sctx.fill();
      sctx.strokeStyle='rgba(80,60,60,.1)'; sctx.lineWidth=.38; sctx.stroke();

      if(avg<wn){
        const pw0=isoP(c,r,(wn+wo)*2.65,viewAng),pw1=isoP(c+1,r,(wn+wo)*2.65,viewAng);
        const pw2=isoP(c+1,r+1,(wn+wo)*2.65,viewAng),pw3=isoP(c,r+1,(wn+wo)*2.65,viewAng);
        const depth=Math.min(1,(wn-avg)*6);
        const wg=sctx.createLinearGradient(pw0.x,pw0.y,pw2.x,pw2.y);
        wg.addColorStop(0,`rgba(109,200,232,${.40+depth*.32})`);
        wg.addColorStop(1,`rgba(58,155,191,${.48+depth*.28})`);
        sctx.fillStyle=wg;
        sctx.beginPath(); sctx.moveTo(pw0.x,pw0.y); sctx.lineTo(pw1.x,pw1.y); sctx.lineTo(pw2.x,pw2.y); sctx.lineTo(pw3.x,pw3.y); sctx.closePath(); sctx.fill();
        if(Math.sin(waveTime*4+r*.85+c*1.15)>.9){ sctx.fillStyle='rgba(189,232,255,.38)'; sctx.fill(); }
        if(Math.random()>.97) bubbles.push({x:pw0.x,y:pw0.y,vx:(Math.random()-.5)*1.3,vy:-Math.random()*.75,life:1,r:1.8+Math.random()*3});

        // ── 3D Water Caustics (Voronoi-style light patches) ──
        if(depth > 0.08 && (r+c)%3===0){
          const cx3=(pw0.x+pw2.x)/2, cy3=(pw0.y+pw2.y)/2;
          const cSize = 3 + depth*5;
          // Three overlapping caustic patches per cell, animated by waveTime
          for(let ci2=0;ci2<2;ci2++){
            const seed = r*137+c*53+ci2*71;
            const cx4 = cx3 + Math.sin(waveTime*1.7+seed*.08)*cSize*1.4;
            const cy4 = cy3 + Math.cos(waveTime*2.1+seed*.11)*cSize*.9;
            const cr2 = cSize*(0.5+0.5*Math.sin(waveTime*3.2+seed*.19));
            const ca  = depth * 0.22 * Math.max(0,Math.sin(waveTime*2.4+seed*.23));
            if(ca < 0.02) continue;
            const cg2 = sctx.createRadialGradient(cx4-cr2*.3,cy4-cr2*.3,0.5,cx4,cy4,cr2);
            cg2.addColorStop(0,`rgba(255,255,255,${ca*1.6})`);
            cg2.addColorStop(0.5,`rgba(180,235,255,${ca})`);
            cg2.addColorStop(1,`rgba(109,200,232,0)`);
            sctx.save();
            sctx.globalAlpha=1;
            sctx.fillStyle=cg2;
            sctx.beginPath(); sctx.ellipse(cx4,cy4,cr2,cr2*.55,0,0,Math.PI*2); sctx.fill();
            sctx.restore();
          }
        }
      }
    }
  }

  // Water surface bubbles
  sctx.save();
  bubbles.forEach(b=>{ sctx.globalAlpha=b.life*.5; sctx.strokeStyle='rgba(189,232,255,.8)'; sctx.lineWidth=1.2; sctx.beginPath(); sctx.arc(b.x,b.y,b.r,0,Math.PI*2); sctx.stroke(); });
  sctx.restore();

  // ── 🏙️ 3D BUILDINGS, TREES & ROADS ──
  const seedRand=(s)=>{ let x=Math.sin(s+1)*43758.5453; return x-Math.floor(x); };

  // City-specific building density and height
  const cityBuildCfg = {
    taipei:    { count:95, maxH:0.38, minH:0.05, skyscraperChance:0.35, label:'Taipei' },
    tainan:    { count:55, maxH:0.16, minH:0.03, skyscraperChance:0.05, label:'Tainan' },
    kaohsiung: { count:65, maxH:0.22, minH:0.04, skyscraperChance:0.12, label:'Kaohsiung' },
    hualien:   { count:28, maxH:0.10, minH:0.02, skyscraperChance:0.02, label:'Hualien' },
  };
  const buildCfg = cityBuildCfg[currentDEMKey] || cityBuildCfg.tainan;

  // Roads (draw first)
  const roadPaths = [
    [[20,18],[22,36],[28,52],[30,62]],
    [[40,15],[42,30],[44,50],[46,66]],
    [[18,30],[28,32],[42,33],[58,35]],
    [[20,45],[32,46],[46,48],[58,50]],
  ];
  // Taipei gets extra roads (dense grid)
  if(currentDEMKey==='taipei'){
    roadPaths.push([[10,20],[12,35],[15,50],[18,65]]);
    roadPaths.push([[30,10],[32,25],[35,40],[38,55],[40,70]]);
    roadPaths.push([[50,12],[52,28],[55,45],[57,60]]);
    roadPaths.push([[8,40],[20,42],[35,44],[50,46],[65,48]]);
  }
  roadPaths.forEach(path=>{
    sctx.save();
    sctx.strokeStyle='rgba(210,200,180,.72)'; sctx.lineWidth=2.8; sctx.lineCap='round'; sctx.lineJoin='round';
    sctx.beginPath();
    path.forEach(([rc,cc],i)=>{
      const h=gh(rc,cc);
      if(h>=wn-.02){
        const p=isoP(cc,rc,h*2.65,viewAng);
        i===0?sctx.moveTo(p.x,p.y):sctx.lineTo(p.x,p.y);
      }
    });
    sctx.stroke();
    sctx.strokeStyle='rgba(255,255,230,.38)'; sctx.lineWidth=0.9; sctx.setLineDash([4,5]);
    sctx.lineDashOffset = -(waveTime*18)%18;
    sctx.beginPath();
    path.forEach(([rc,cc],i)=>{
      const h=gh(rc,cc);
      if(h>=wn-.02){
        const p=isoP(cc,rc,h*2.65,viewAng);
        i===0?sctx.moveTo(p.x,p.y):sctx.lineTo(p.x,p.y);
      }
    });
    sctx.stroke(); sctx.setLineDash([]);
    sctx.restore();
  });

  // Generate buildings
  const buildingSeeds = [];
  for(let bi=0;bi<buildCfg.count;bi++){
    const isSky = seedRand(bi*31+5) < buildCfg.skyscraperChance;
    const br = Math.floor(seedRand(bi*7)*58)+4;
    const bc = Math.floor(seedRand(bi*11)*58)+4;
    const bh = isSky
      ? (buildCfg.maxH*0.55 + seedRand(bi*13)*(buildCfg.maxH*0.45))
      : (buildCfg.minH + seedRand(bi*13)*(buildCfg.maxH*0.45));
    const bw = isSky ? (0.35 + seedRand(bi*17)*0.45) : (0.55 + seedRand(bi*17)*0.7);
    buildingSeeds.push({r:br,c:bc,bh,bw,seed:bi,isSky});
  }
  buildingSeeds.sort((a,b)=>(a.r+a.c)-(b.r+b.c));

  buildingSeeds.forEach(({r:br,c:bc,bh:bHeight,bw,seed:bi,isSky})=>{
    const terrH = gh(br,bc);
    if(terrH < wn) return;
    const baseH = terrH*2.65;
    const topH = baseH + bHeight*10.5;
    const hs = bw * 0.65;

    const pBL = isoP(bc-hs,  br+hs, baseH, viewAng);
    const pBR = isoP(bc+hs,  br+hs, baseH, viewAng);
    const pFL = isoP(bc-hs,  br-hs, baseH, viewAng);
    const pFR = isoP(bc+hs,  br-hs, baseH, viewAng);
    const pTBL= isoP(bc-hs,  br+hs, topH,  viewAng);
    const pTBR= isoP(bc+hs,  br+hs, topH,  viewAng);
    const pTFL= isoP(bc-hs,  br-hs, topH,  viewAng);
    const pTFR= isoP(bc+hs,  br-hs, topH,  viewAng);

    // Skyscraper = glass/steel, regular = concrete
    let wallL, wallR, roofC;
    if(isSky){
      const hue = 190 + seedRand(bi*43)*30;
      wallL  = `hsla(${hue},35%,52%,.92)`;
      wallR  = `hsla(${hue},50%,72%,.88)`;
      roofC  = `hsla(${hue},30%,45%,.95)`;
    } else {
      const t2 = bi%4;
      wallL  = t2===0?'#c0c8d0':t2===1?'#d0c0b0':t2===2?'#b8c0b0':'#c8c0c8';
      wallR  = t2===0?'#a0a8b0':t2===1?'#b0a090':t2===2?'#98a090':'#a898a8';
      roofC  = t2===0?'#8898a8':t2===1?'#a08870':t2===2?'#809878':'#988890';
    }

    sctx.save();
    // Left face
    sctx.fillStyle=wallL;
    sctx.beginPath(); sctx.moveTo(pBL.x,pBL.y); sctx.lineTo(pFL.x,pFL.y); sctx.lineTo(pTFL.x,pTFL.y); sctx.lineTo(pTBL.x,pTBL.y); sctx.closePath(); sctx.fill();
    sctx.strokeStyle='rgba(0,0,0,.08)'; sctx.lineWidth=.4; sctx.stroke();
    // Right face
    sctx.fillStyle=wallR;
    sctx.beginPath(); sctx.moveTo(pBR.x,pBR.y); sctx.lineTo(pFL.x,pFL.y); sctx.lineTo(pTFL.x,pTFL.y); sctx.lineTo(pTFR.x,pTFR.y); sctx.closePath(); sctx.fill();
    sctx.stroke();
    // Roof
    sctx.fillStyle=roofC;
    sctx.beginPath(); sctx.moveTo(pTBL.x,pTBL.y); sctx.lineTo(pTBR.x,pTBR.y); sctx.lineTo(pTFR.x,pTFR.y); sctx.lineTo(pTFL.x,pTFL.y); sctx.closePath(); sctx.fill();
    sctx.stroke();

    // Glass windows — skyscrapers get grid pattern, regular get dots
    if(isSky && bHeight > 0.08){
      const floors = Math.floor(bHeight/0.028);
      const cols2 = 2;
      for(let wr=0;wr<floors;wr++) for(let wc2=0;wc2<cols2;wc2++){
        const wfx=(wc2+.5)/(cols2+.5)*0.7+0.1, wfy=(wr+.5)/(floors+.5);
        const wx2 = pFL.x+(pTFL.x-pFL.x)*wfy+(pBR.x-pFL.x)*wfx*.48;
        const wy2 = pFL.y+(pTFL.y-pFL.y)*wfy+(pBR.y-pFL.y)*wfx*.48;
        const lit = seedRand(bi*29+wr*7+wc2) > 0.25;
        sctx.fillStyle = lit ? 'rgba(200,230,255,.78)' : 'rgba(40,60,100,.45)';
        sctx.beginPath(); sctx.rect(wx2-1,wy2-1.8,2,3.2); sctx.fill();
      }
      // Antenna / spire on tall skyscrapers
      if(bHeight > 0.22){
        const ant = isoP(bc, br, topH+0.6, viewAng);
        sctx.strokeStyle='rgba(100,120,140,.8)'; sctx.lineWidth=1;
        sctx.beginPath(); sctx.moveTo(pTFR.x+(pTFL.x-pTFR.x)*.5,pTFR.y+(pTFL.y-pTFR.y)*.5); sctx.lineTo(ant.x,ant.y); sctx.stroke();
        // Blinking light
        const blinkOn = Math.sin(waveTime*3+bi)>.5;
        if(blinkOn){ sctx.fillStyle='rgba(255,80,80,.9)'; sctx.beginPath(); sctx.arc(ant.x,ant.y,1.5,0,Math.PI*2); sctx.fill(); }
      }
    } else if(bHeight > 0.05){
      const rows2=2, cols2=2;
      for(let wr=0;wr<rows2;wr++) for(let wc2=0;wc2<cols2;wc2++){
        const wfx=(wc2+1)/(cols2+1), wfy=(wr+1)/(rows2+1);
        const wx2 = pFL.x+(pTFL.x-pFL.x)*wfy+(pBR.x-pFL.x)*wfx*.45;
        const wy2 = pFL.y+(pTFL.y-pFL.y)*wfy+(pBR.y-pFL.y)*wfx*.45;
        const lit = seedRand(bi*29+wr*7+wc2) > 0.38;
        sctx.fillStyle = lit ? 'rgba(255,240,180,.72)' : 'rgba(80,90,120,.32)';
        sctx.beginPath(); sctx.rect(wx2-1.1,wy2-1.4,2.2,2.8); sctx.fill();
      }
    }
    sctx.restore();
  });

  // Trees
  const treeCounts = {taipei:25, tainan:40, kaohsiung:32, hualien:50};
  const treeCount = treeCounts[currentDEMKey]||40;
  const treeSeeds = [];
  for(let ti=0;ti<treeCount;ti++){
    const tr2=Math.floor(seedRand(ti*23+3)*55)+4;
    const tc2=Math.floor(seedRand(ti*19+7)*55)+4;
    treeSeeds.push({r:tr2,c:tc2,seed:ti});
  }
  treeSeeds.forEach(({r:tr2,c:tc2,seed:ti})=>{
    const terrH=gh(tr2,tc2);
    if(terrH < wn) return;
    if(terrH > 0.6) return;
    const onBuilding = buildingSeeds.some(b=>Math.abs(b.r-tr2)<2&&Math.abs(b.c-tc2)<2);
    if(onBuilding) return;
    const baseH=terrH*2.65;
    const tH=1.8+seedRand(ti*31)*2.2;
    const base=isoP(tc2,tr2,baseH,viewAng);
    const top=isoP(tc2,tr2,baseH+tH,viewAng);
    const treeType = ti%3;
    sctx.save();
    sctx.strokeStyle='rgba(110,75,40,.8)'; sctx.lineWidth=1.6;
    sctx.beginPath(); sctx.moveTo(base.x,base.y); sctx.lineTo(top.x,top.y); sctx.stroke();
    if(treeType===0){
      for(let tl=0;tl<3;tl++){
        const ly=(top.y-base.y)*(0.4+tl*.2);
        const tw2=5-tl*1.2;
        sctx.fillStyle=`rgba(${50+tl*15},${130+tl*20},${60+tl*8},.82)`;
        sctx.beginPath(); sctx.moveTo(top.x,top.y+ly-tw2*.5);
        sctx.lineTo(top.x-tw2,top.y+ly+tw2*.8); sctx.lineTo(top.x+tw2,top.y+ly+tw2*.8); sctx.closePath(); sctx.fill();
      }
    } else if(treeType===1){
      const r2=3.5+seedRand(ti*41)*.5;
      const cg2=sctx.createRadialGradient(top.x-r2*.3,top.y-r2*.3,0.5,top.x,top.y,r2);
      cg2.addColorStop(0,'rgba(120,200,80,.9)'); cg2.addColorStop(.6,'rgba(70,150,50,.8)'); cg2.addColorStop(1,'rgba(40,110,30,.5)');
      sctx.fillStyle=cg2;
      sctx.beginPath(); sctx.arc(top.x,top.y,r2,0,Math.PI*2); sctx.fill();
    } else {
      for(let fp=0;fp<5;fp++){
        const fa=(fp/5)*Math.PI*2;
        sctx.strokeStyle=`rgba(60,130,40,.7)`; sctx.lineWidth=1.2;
        sctx.beginPath(); sctx.moveTo(top.x,top.y);
        sctx.quadraticCurveTo(top.x+Math.cos(fa)*5,top.y+Math.sin(fa)*3,top.x+Math.cos(fa)*8,top.y+Math.sin(fa)*4+2);
        sctx.stroke();
      }
    }
    sctx.restore();
  });

  // ── 🌊 FLOOD WAVE FRONT FOAM ──
  if(wn > 0.05){
    const foamMargin = 0.04;
    sctx.save();
    for(let r=GRID-1;r>=0;r--){
      for(let c=0;c<GRID;c++){
        const avg=(gh(r,c)+gh(r+1,c)+gh(r,c+1)+gh(r+1,c+1))/4;
        const atBoundary = avg < wn && avg > wn - foamMargin;
        if(!atBoundary) continue;
        const wo=waveInt*.018*(Math.sin(waveTime*2+r*.35+c*.45));
        const pw=isoP(c+.5,r+.5,(wn+wo)*2.65,viewAng);
        const foamPulse = 0.5 + 0.5*Math.sin(waveTime*6 + r*.7 + c*.5);
        const fw = (4 + foamPulse*5);
        const fh = (2 + foamPulse*2.5);
        sctx.globalAlpha = 0.55 + foamPulse*0.3;
        sctx.fillStyle = `rgba(235,248,255,${0.7+foamPulse*.25})`;
        sctx.beginPath(); sctx.ellipse(pw.x, pw.y, fw, fh, 0, 0, Math.PI*2); sctx.fill();
      }
    }
    sctx.restore();
  }

  // ── 〰️ WATER SURFACE RIPPLE RINGS ──
  if(wn > 0.05){
    // Spawn new ripple ~every 0.35s of waveTime
    if(Math.floor(waveTime/0.35) !== Math.floor((waveTime-0.016*(1+waveInt*.5))/0.35)){
      const numSpawn = Math.floor(1 + wn * 3);
      for(let k=0;k<numSpawn;k++){
        // Find a random flooded position
        const ri=Math.floor(Math.random()*GRID), ci=Math.floor(Math.random()*GRID);
        if(gh(ri,ci) < wn){
          const wo=waveInt*.018*(Math.sin(waveTime*2+ri*.35+ci*.45));
          const pw=isoP(ci,ri,(wn+wo)*2.65,viewAng);
          surfaceRipples.push({x:pw.x, y:pw.y, r:0, life:1, maxR:20+Math.random()*30});
        }
      }
    }
    // Update and draw ripples
    sctx.save();
    surfaceRipples = surfaceRipples.filter(rr=>rr.life>0);
    surfaceRipples.forEach(rr=>{
      rr.r += 0.7;
      rr.life -= 0.022;
      const progress = rr.r / rr.maxR;
      sctx.globalAlpha = rr.life * 0.55 * (1-progress*.5) * wn;
      sctx.strokeStyle = 'rgba(189,232,255,.9)';
      sctx.lineWidth = 1;
      sctx.beginPath();
      sctx.ellipse(rr.x, rr.y, rr.r, rr.r*0.38, 0, 0, Math.PI*2);
      sctx.stroke();
    });
    sctx.restore();
  }

  // Rain drops
  sctx.save();
  drops.forEach(d=>{ sctx.globalAlpha=d.life*.48; sctx.strokeStyle='rgba(160,210,255,.75)'; sctx.lineWidth=1; sctx.beginPath(); sctx.moveTo(d.x,d.y); sctx.lineTo(d.x+d.vx*2.5,d.y+d.vy*2); sctx.stroke(); });
  sctx.restore();

  // ── WIND EFFECT ──
  if(windSpd>4){
    const wStr=windSpd/100; // 0..1
    sctx.save();

    // Animated wind streaks — curving lines that scroll across
    const numStreaks=Math.floor(4+wStr*14);
    for(let i=0;i<numStreaks;i++){
      const seed=i*137.5;
      const speed=windSpd*1.2;
      const wy2=simH*((seed%100)/100*.8+.08);
      const phase=(waveTime*speed*0.5+seed*3.7)%(simW*1.5)-simW*.25;
      const wlen=(22+wStr*90)*(0.6+i%3*.3);
      const alpha=wStr*(0.15+i%3*.08);
      const thick=0.6+wStr*1.8;
      // Main streak
      sctx.globalAlpha=alpha;
      sctx.strokeStyle=`rgba(200,225,255,1)`;
      sctx.lineWidth=thick;
      sctx.lineCap='round';
      sctx.beginPath();
      sctx.moveTo(phase, wy2);
      // Slight curve for realism
      sctx.bezierCurveTo(phase-wlen*.3, wy2+2, phase-wlen*.7, wy2-1, phase-wlen, wy2);
      sctx.stroke();
      // Fading tail
      const grad=sctx.createLinearGradient(phase,wy2,phase-wlen,wy2);
      grad.addColorStop(0,`rgba(220,235,255,${alpha*1.5})`);
      grad.addColorStop(1,'rgba(220,235,255,0)');
      sctx.strokeStyle=grad; sctx.lineWidth=thick*1.6;
      sctx.beginPath(); sctx.moveTo(phase,wy2); sctx.lineTo(phase-wlen,wy2); sctx.stroke();
    }

    // Debris / leaves blowing at high wind
    if(windSpd>45){
      const numDebris=Math.floor((windSpd-45)/8);
      const debrisChars=['🍃','🌿','○','◌','·'];
      for(let i=0;i<numDebris;i++){
        const seed2=i*89.3;
        const wy2=simH*((seed2%100)/100*.75+.12);
        const phase2=(waveTime*windSpd*0.9+seed2*5.1)%(simW*1.6)-simW*.3;
        const wobble=Math.sin(waveTime*3+i*1.7)*8;
        sctx.globalAlpha=wStr*.6;
        sctx.font=`${10+i%3*4}px serif`;
        sctx.textAlign='center';
        sctx.fillText(debrisChars[i%debrisChars.length], phase2, wy2+wobble);
      }
    }

    // Wind direction indicator arrow in corner
    if(windSpd>20){
      sctx.globalAlpha=0.55;
      const ax=simW*.92, ay=simH*.18;
      sctx.fillStyle='rgba(200,225,255,.8)';
      sctx.strokeStyle='rgba(150,190,240,.9)'; sctx.lineWidth=2;
      sctx.font=`bold ${11+(wStr*4).toFixed(0)}px Nunito,sans-serif`;
      sctx.textAlign='center';
      sctx.fillText('💨', ax, ay);
      sctx.fillStyle='rgba(100,150,220,.8)';
      sctx.font=`bold 9px Nunito,sans-serif`;
      sctx.fillText(`${Math.round(windSpd*1.4)} km/h`, ax, ay+14);
    }

    sctx.restore();
  }

  // ── TEMPERATURE EFFECT ──
  const tmpNorm=(tempC-15)/27; // 0(cold)..1(hot)

  if(tempC>=35){
    // HOT — heat shimmer waves + sun haze
    sctx.save();
    const heatStr=(tempC-35)/7; // 0..1
    // Rising heat shimmer bands
    const numBands=Math.floor(5+heatStr*8);
    for(let i=0;i<numBands;i++){
      const seed=i*61.3;
      const bx=simW*((seed%100)/100);
      const by=simH*(.35+((seed*1.7)%100)/100*.5);
      const bw=20+heatStr*40;
      const bh=60+heatStr*80;
      const phase=Math.sin(waveTime*2.5+i*0.9)*6;
      const alpha=heatStr*0.06*(1+Math.sin(waveTime*3+i));
      const hg=sctx.createLinearGradient(bx,by+bh,bx+phase,by);
      hg.addColorStop(0,'rgba(255,200,80,0)');
      hg.addColorStop(.4,`rgba(255,180,60,${alpha})`);
      hg.addColorStop(1,'rgba(255,220,120,0)');
      sctx.fillStyle=hg;
      sctx.beginPath(); sctx.ellipse(bx+phase,by,bw*.5,bh*.5,0,0,Math.PI*2); sctx.fill();
    }
    // Sun glow in upper right
    sctx.globalAlpha=0.25+heatStr*.3;
    const sg=sctx.createRadialGradient(simW*.88,simH*.08,5,simW*.88,simH*.08,80+heatStr*40);
    sg.addColorStop(0,'rgba(255,240,120,0.9)');
    sg.addColorStop(.4,'rgba(255,200,80,0.4)');
    sg.addColorStop(1,'rgba(255,180,60,0)');
    sctx.fillStyle=sg; sctx.fillRect(0,0,simW,simH*.4);
    sctx.globalAlpha=1;
    // Temp label
    sctx.globalAlpha=0.7; sctx.font='bold 11px Nunito,sans-serif'; sctx.textAlign='center';
    sctx.fillStyle='rgba(255,160,40,.9)';
    sctx.fillText(`🌡️ ${Math.round(tempC)}°C — Heat Warning`, simW*.5, simH*.1);
    sctx.restore();

  } else if(tempC<=20){
    // COLD — snowflakes falling
    sctx.save();
    const coldStr=(20-tempC)/5; // 0..1
    const numFlakes=Math.floor(coldStr*18);
    for(let i=0;i<numFlakes;i++){
      const seed=i*73.1;
      const fx=((waveTime*18+seed*8.3))%(simW) ;
      const fy=(waveTime*22+seed*15.7+Math.sin(waveTime+i)*(simW*.04))%simH;
      const fsize=3+i%4*2;
      const falpha=coldStr*(0.3+i%3*.15);
      sctx.globalAlpha=falpha;
      sctx.font=`${fsize+8}px serif`; sctx.textAlign='center';
      sctx.fillText('❄', fx, fy);
    }
    // Cold blue tint overlay
    sctx.globalAlpha=coldStr*.08;
    sctx.fillStyle='rgba(180,220,255,1)';
    sctx.fillRect(0,0,simW,simH);
    // Temp label
    sctx.globalAlpha=0.7; sctx.font='bold 11px Nunito,sans-serif'; sctx.textAlign='center';
    sctx.fillStyle='rgba(80,160,240,.9)';
    sctx.fillText(`❄️ ${Math.round(tempC)}°C — Cold Alert`, simW*.5, simH*.1);
    sctx.restore();
  }

  // Typhoon track trail
  drawTyphoonTrack(sctx);
  // Typhoon eye
  drawTyphoonEye(sctx, waveTime);
  // Live weather overlay
  drawWeatherOverlay(sctx, waveTime);
  // Landmark
  drawLandmark(sctx, waterLvl, waveTime);

  // Vignette
  const vig=sctx.createRadialGradient(simW*.5,simH*.5,simH*.2,simW*.5,simH*.5,simH*.9);
  vig.addColorStop(0,'transparent'); vig.addColorStop(1,'rgba(240,245,255,.12)');
  sctx.fillStyle=vig; sctx.fillRect(0,0,simW,simH);

  // ── 🔭 Tilt-shift depth-of-field overlay ──
  // Near edge (bottom): blur gradient
  const tiltNear = sctx.createLinearGradient(0, simH*0.72, 0, simH);
  tiltNear.addColorStop(0,'rgba(240,246,255,0)');
  tiltNear.addColorStop(0.5,'rgba(240,246,255,0.22)');
  tiltNear.addColorStop(1,'rgba(240,246,255,0.62)');
  sctx.fillStyle=tiltNear; sctx.fillRect(0,simH*0.72,simW,simH*0.28);
  // Far edge (top): blur gradient
  const tiltFar = sctx.createLinearGradient(0, 0, 0, simH*0.3);
  tiltFar.addColorStop(0,'rgba(235,245,255,0.58)');
  tiltFar.addColorStop(0.6,'rgba(235,245,255,0.18)');
  tiltFar.addColorStop(1,'rgba(235,245,255,0)');
  sctx.fillStyle=tiltFar; sctx.fillRect(0,0,simW,simH*0.3);
}

// ══════════════════════════════════════════
//  ADVANCED HYDROLOGY ENGINE
//  Real equations, real parameters
// ══════════════════════════════════════════

// Manning's equation: Q = (1/n) * A * R^(2/3) * S^(1/2)
// n = Manning roughness, A = cross-sectional area, R = hydraulic radius, S = slope
function manningsDischarge(wlM, waveIntensity){
  const n_rough = 0.035; // natural channel roughness
  const channelWidth = 80 + wlM * 12; // m, widens with flood
  const depth = wlM;
  if(depth <= 0) return 0;
  const A = channelWidth * depth;
  const P = channelWidth + 2*depth; // wetted perimeter
  const R = A/P;
  const S = 0.002 + waveIntensity*0.003; // slope influenced by waves
  return (1/n_rough) * A * Math.pow(R, 2/3) * Math.pow(S, 0.5);
}

// Flow velocity from discharge
function flowVelocity(Q, wlM){
  const channelWidth = 80 + wlM * 12;
  if(wlM<=0 || channelWidth<=0) return 0;
  return Q / (channelWidth * wlM);
}

// Reynolds number: Re = ρVL/μ  (water: ρ=1000, μ=0.001)
function reynoldsNumber(V, wlM){
  const rho=1000, mu=0.001;
  return (rho * V * Math.max(0.01, wlM)) / mu;
}

// Froude number: Fr = V / sqrt(g*d)  — <1 subcritical, >1 supercritical
function froudeNumber(V, wlM){
  const g=9.81;
  if(wlM<=0) return 0;
  return V / Math.sqrt(g * wlM);
}

// Hydrostatic pressure: P = ρgh (kPa)
function hydrostaticPressure(wlM){
  return (1000 * 9.81 * wlM) / 1000; // kPa
}

// SCS Curve Number runoff model: Q = (P - Ia)² / (P - Ia + S)
// CN influenced by soil saturation
function scsCurveNumberRunoff(rainfallMmH, satPct){
  if(rainfallMmH<=0) return 0;
  const CN = 60 + satPct * 0.38; // CN 60-98 based on saturation
  const S = (25400/CN) - 254; // potential max retention (mm)
  const Ia = 0.2 * S; // initial abstraction
  const P = rainfallMmH;
  if(P <= Ia) return 0;
  return Math.pow(P - Ia, 2) / (P - Ia + S);
}

// Horton infiltration: f = fc + (f0-fc)*e^(-kt)
function hortonInfiltration(satPct, timeMin){
  const f0 = 25; // initial infiltration rate mm/h
  const fc = 2 + (1-satPct/100)*8; // final rate, lower when saturated
  const k = 0.05;
  return fc + (f0-fc)*Math.exp(-k*timeMin);
}

// Penman-Monteith simplified evapotranspiration (mm/day)
function penmanMonteithEvap(tempCelsius, windKmh){
  const Rn = 8 + tempCelsius*0.25; // net radiation proxy
  const es = 0.6108*Math.exp(17.27*tempCelsius/(tempCelsius+237.3)); // saturation vapour
  const ea = es * 0.65;
  const delta = 4098*es/Math.pow(tempCelsius+237.3,2);
  const gamma = 0.067; // psychrometric constant
  const u2 = windKmh/3.6;
  const ET = (0.408*delta*Rn + gamma*(900/(tempCelsius+273))*u2*(es-ea)) / (delta + gamma*(1+0.34*u2));
  return Math.max(0, ET);
}

// ── UPDATE UI ──
let curLoc='Tainan Basin', curCountry='Taiwan', simTimeMins=0;
function updateAll(){
  const wl  = parseFloat(document.getElementById('s-wl').value);
  const wi  = parseFloat(document.getElementById('s-wi').value);
  const rr  = parseFloat(document.getElementById('s-rr').value);
  const ws  = parseFloat(document.getElementById('s-ws').value);
  const tmp = parseFloat(document.getElementById('s-tmp').value);
  const va  = parseFloat(document.getElementById('s-va').value);
  const sat = parseFloat(document.getElementById('s-sat').value);

  waterLvl=wl; waveInt=wi/100*1.8; rainR=rr; windSpd=ws; viewAng=va; tempC=tmp; saturation=sat;
  // Update ambient sounds based on current params
  try{ updateAmbientSounds(wl, rr, ws); } catch(e){}
  // Eye reaction
  try{ updateEyeReaction(wl); } catch(e){}
  // Header weather particles
  try{ updateHeaderWeather(rr, ws, typhMode); } catch(e){}

  // Slider track fills
  const sliders=[
    ['s-wl', wl,    'linear-gradient(90deg,#6dc8e8,#3a9bbf)'],
    ['s-wi', wi,    'linear-gradient(90deg,#c9b8ff,#a89cff)'],
    ['s-rr', rr,    'linear-gradient(90deg,#bde8ff,#6dc8e8)'],
    ['s-ws', ws,    'linear-gradient(90deg,#d0f5eb,#7de8b0)'],
    ['s-tmp',(tmp-15)/27*100,'linear-gradient(90deg,#ffe599,#ffb347)'],
    ['s-va', (va-15)/57*100,'linear-gradient(90deg,#b8f2e0,#6dc8e8)'],
    ['s-sat',sat,   'linear-gradient(90deg,#ffb7c5,#ff9eb5)'],
  ];
  sliders.forEach(([id,pct,clr])=>{ document.getElementById(id).style.background=`${clr} ${pct}%,rgba(180,160,220,.15) ${pct}%`; });

  // Labels
  document.getElementById('v-wl').textContent=(wl/10).toFixed(2)+' m';
  document.getElementById('v-wi').textContent=Math.round(wi)+'%';
  document.getElementById('v-rr').textContent=Math.round(rr*3)+' mm/h';
  document.getElementById('v-ws').textContent=Math.round(ws*1.4)+' km/h';
  document.getElementById('v-tmp').textContent=Math.round(tmp)+'°C';
  document.getElementById('v-va').textContent=Math.round(va)+'°';
  document.getElementById('v-sat').textContent=Math.round(sat)+'%';

  const wlM=(wl/10); // convert 0-100 to 0-10 metres
  document.getElementById('wl-big').textContent=wlM.toFixed(2);
  document.getElementById('bs-wl').textContent=wlM.toFixed(2)+'m';

  // Water emoji
  document.getElementById('wl-emoji').textContent=wl>78?'🚨':wl>55?'😱':wl>28?'👀':wl>5?'💧':'💧';

  // Tank
  document.getElementById('tank-water').style.height=wl+'%';
  const fishBottom=Math.min(82,wl+5);
  document.getElementById('tank-fish-cv').style.bottom=fishBottom+'%';
  // color changes with wl — no text content needed for canvas fish

  // ── ADVANCED PHYSICS ──
  const rainMmH = rr*3;
  const windKmH = ws*1.4;
  const Q       = manningsDischarge(wlM, wi/100);
  const V       = flowVelocity(Q, wlM);
  const Re      = reynoldsNumber(V, wlM);
  const Fr      = froudeNumber(V, wlM);
  const Pr      = hydrostaticPressure(wlM);
  const runoff  = scsCurveNumberRunoff(rainMmH, sat);
  const infiltr = hortonInfiltration(sat, simTimeMins);
  const evap    = penmanMonteithEvap(tmp, windKmH);

  // Display physics
  document.getElementById('pp-discharge').textContent=Q.toFixed(0);
  document.getElementById('pp-velocity').textContent=V.toFixed(2);
  document.getElementById('pp-pressure').textContent=Pr.toFixed(1);
  document.getElementById('pp-runoff').textContent=runoff.toFixed(1);
  document.getElementById('pp-evap').textContent=evap.toFixed(2);
  document.getElementById('pp-infiltr').textContent=infiltr.toFixed(1);
  // Physics overlay
  document.getElementById('pc-re').textContent=(Re/1000).toFixed(1)+'k';
  document.getElementById('pc-fr').textContent=Fr.toFixed(3);
  document.getElementById('pc-q').textContent=Q.toFixed(0)+' m³/s';
  document.getElementById('pc-evap').textContent=evap.toFixed(1)+' mm/d';

  // ── RISK ──
  const pop  = Math.round(wl*2450);
  const dmg  = Math.round(wl*wl*180000);

  function setRisk(badgeId,barId,subId,pct,label,color,sub){
    const el=document.getElementById(badgeId);
    const colors={safe:['rgba(125,232,176,.2)','#2a9060','rgba(125,232,176,.45)'],
                  warn:['rgba(255,200,100,.2)','#c07010','rgba(255,200,100,.45)'],
                  crit:['rgba(255,112,150,.2)','#c03060','rgba(255,112,150,.45)']};
    const [bg,tc,bc]=colors[color];
    el.textContent=label; el.style.cssText=`background:${bg};color:${tc};border:1.5px solid ${bc};border-radius:100px;padding:2px 9px;font-family:'Fredoka One',cursive;font-size:.65rem;`;
    document.getElementById(barId).style.width=Math.max(2,pct)+'%';
    document.getElementById(subId).textContent=sub;
  }

  const fCol=wl<22?'safe':wl<55?'warn':'crit';
  setRisk('rb-flood','rf-flood','rs-flood',wl,
    wl<22?'LOW ✓':wl<55?'MOD ⚡':wl<75?'HIGH':'CRIT 🚨',fCol,
    wl<5?'All clear — no flooding detected':wl<30?'Minor inundation possible':wl<60?'Significant flood risk!':'Critical — immediate evacuation!');
  document.getElementById('rf-flood').style.background=wl<22?'linear-gradient(90deg,var(--mint),var(--safe))':wl<55?'linear-gradient(90deg,var(--sun),var(--warn))':'linear-gradient(90deg,var(--sakura),var(--danger))';

  setRisk('rb-pop','rf-pop','rs-pop',Math.min(100,wl*1.1),
    pop>0?pop.toLocaleString()+' at risk':'0 safe', pop>50000?'crit':pop>10000?'warn':'safe',
    pop>0?pop.toLocaleString()+' residents in danger zone':'0 residents in danger zone');
  document.getElementById('rf-pop').style.background='linear-gradient(90deg,var(--sakura),var(--coral))';
  document.getElementById('bs-pop').textContent=pop.toLocaleString();

  const infCol=wl>45?'crit':wl>25?'warn':'safe';
  setRisk('rb-infra','rf-infra','rs-infra',Math.max(2,wl*.9),
    wl>45?'DAMAGED':wl>25?'AT RISK':'SAFE ✓',infCol,
    wl>45?'Roads and bridges compromised!':wl>25?'Infrastructure at risk':'Roads and bridges nominal');
  document.getElementById('rf-infra').style.background='linear-gradient(90deg,var(--lavender),#a89cff)';

  const farmCol=wl>25?'crit':wl>10?'warn':'safe';
  setRisk('rb-farm','rf-farm','rs-farm',Math.max(2,wl*.8),
    wl>25?'FLOOD':'SAFE ✓',farmCol,
    wl>25?'Farmland flooding — crop loss detected':wl>10?'Farmers on alert~':'Farmland and rice paddies safe');
  document.getElementById('rf-farm').style.background='linear-gradient(90deg,var(--sun),var(--warn))';

  // Zones
  function setZone(zpId,zstId,warn,crit){
    const flooded=wl>crit, warning=wl>warn;
    document.getElementById(zstId).textContent=flooded?'FLOOD!':warning?'WARN':'DRY';
    document.getElementById(zstId).style.color=flooded?'var(--danger)':warning?'var(--warn)':'var(--safe)';
    document.getElementById(zpId).style.background=flooded?'rgba(255,112,150,.1)':warning?'rgba(255,200,100,.08)':'rgba(125,232,176,.06)';
    document.getElementById(zpId).style.borderColor=flooded?'rgba(255,112,150,.4)':warning?'rgba(255,200,100,.3)':'rgba(200,180,230,.2)';
  }
  setZone('zp-a','zst-a',15,20);
  setZone('zp-b','zst-b',35,50);
  setZone('zp-c','zst-c',60,78);

  // Bottom bar
  document.getElementById('bs-dmg').textContent='NT$'+dmg.toLocaleString();
  const eta=autoRun&&wl<95?Math.max(0,Math.round((95-wl)/0.12))+'m':wl>=95?'NOW!':'—';
  document.getElementById('bs-eta').textContent=eta;
  document.getElementById('chip-f').textContent=wl.toFixed(1)+'%';
  document.getElementById('chip-s').textContent=typhMode?'TYPHOON 🌀':autoRun?'RISING':'STATIC';

  // Alert
  document.getElementById('alert-wrap').classList.toggle('show',wl>78);

  // Mascot
  setMascotMsg(wl,rr,ws);
}

document.querySelectorAll('input[type=range]').forEach(el=>el.addEventListener('input',()=>{
  if(!audioUnlocked) getAudioCtx(); // unlock on first slider drag
  updateAll();
}));

// ── BUTTONS ──
let autoWL=0;
document.getElementById('btn-play').addEventListener('click',function(){
  autoRun=!autoRun; typhMode=false;
  this.textContent=autoRun?'⏸ Pause Simulation':'▶ Run Simulation ✦';
  if(autoRun) autoWL=waterLvl;
});

let typhInterval=null, typhPaused=false;

document.getElementById('btn-typhoon').addEventListener('click',()=>{
  // If typhoon is running, PAUSE it
  if(typhMode && !typhPaused && typhInterval){
    typhPaused=true;
    clearInterval(typhInterval); typhInterval=null;
    document.getElementById('btn-typhoon').textContent='▶ Resume Typhoon';
    document.getElementById('btn-typhoon').style.background='linear-gradient(135deg,#7a6adf,#9a8aff)';
    return;
  }
  // If paused, RESUME it
  if(typhMode && typhPaused){
    typhPaused=false;
    document.getElementById('btn-typhoon').textContent='⏸ Pause Typhoon';
    document.getElementById('btn-typhoon').style.background='linear-gradient(135deg,var(--lavender),#a89cff)';
    let t2=waterLvl;
    typhInterval=setInterval(()=>{
      t2=Math.min(94,t2+(t2<40?.25:.5));
      document.getElementById('s-wl').value=t2;
      document.getElementById('s-wi').value=Math.min(100,35+t2*.72);
      simTimeMins+=.5; updateAll();
      if(t2>=94){ clearInterval(typhInterval); typhInterval=null; document.getElementById('btn-typhoon').textContent='⚡ Typhoon Mode'; document.getElementById('btn-typhoon').style.background='linear-gradient(135deg,var(--lavender),#a89cff)'; typhMode=false; }
    },80);
    return;
  }
  // Fresh start
  typhMode=true; typhPaused=false; autoRun=false;
  if(typhInterval){ clearInterval(typhInterval); typhInterval=null; }
  document.getElementById('btn-play').textContent='▶ Run Simulation ✦';
  document.getElementById('btn-typhoon').textContent='⏸ Pause Typhoon';
  document.getElementById('btn-typhoon').style.background='linear-gradient(135deg,var(--lavender),#a89cff)';
  document.getElementById('s-rr').value=88;
  document.getElementById('s-ws').value=75;
  updateAll();
  let t=waterLvl;
  typhInterval=setInterval(()=>{
    t=Math.min(94,t+(t<40?.25:.5));
    document.getElementById('s-wl').value=t;
    document.getElementById('s-wi').value=Math.min(100,35+t*.72);
    simTimeMins+=.5; updateAll();
    if(t>=94){
      clearInterval(typhInterval); typhInterval=null; typhMode=false; typhPaused=false;
      document.getElementById('btn-typhoon').textContent='⚡ Typhoon Mode';
      document.getElementById('btn-typhoon').style.background='linear-gradient(135deg,var(--lavender),#a89cff)';
    }
  },80);
});

document.getElementById('btn-reset').addEventListener('click',()=>{
  autoRun=false; typhMode=false; typhPaused=false;
  if(typhInterval){ clearInterval(typhInterval); typhInterval=null; }
  document.getElementById('btn-typhoon').textContent='⚡ Typhoon Mode';
  document.getElementById('btn-typhoon').style.background='linear-gradient(135deg,var(--lavender),#a89cff)';
  simTimeMins=0; autoWL=0; drops=[]; bubbles=[];
  ['s-wl','s-rr','s-ws'].forEach(id=>document.getElementById(id).value=0);
  document.getElementById('s-wi').value=30;
  document.getElementById('s-tmp').value=28;
  document.getElementById('s-va').value=45;
  document.getElementById('s-sat').value=40;
  document.getElementById('btn-play').textContent='▶ Run Simulation ✦';
  updateAll();
});


