let currentLandmark='tainan', landmarkIntro=0;

function drawChihkanTower(ctx,x,y,sc,wl,t){
  ctx.save(); ctx.translate(x,y);
  const flood=Math.min(1,wl/80), bob=Math.sin(t*1.5)*2*sc;
  ctx.translate(0,bob);
  ctx.fillStyle='rgba(0,0,0,0.10)'; ctx.beginPath(); ctx.ellipse(0,4*sc,22*sc,5*sc,0,0,Math.PI*2); ctx.fill();
  ctx.fillStyle='#c8a878'; ctx.strokeStyle='#9a7a50'; ctx.lineWidth=sc;
  ctx.beginPath(); ctx.roundRect(-22*sc,14*sc,44*sc,10*sc,2*sc); ctx.fill(); ctx.stroke();
  ctx.fillStyle='#e8c890';
  ctx.beginPath(); ctx.roundRect(-14*sc,-18*sc,28*sc,32*sc,2*sc); ctx.fill(); ctx.stroke();
  ctx.fillStyle='#c85030'; ctx.beginPath(); ctx.roundRect(-14*sc,6*sc,28*sc,8*sc,1*sc); ctx.fill();
  ctx.fillStyle='#d8b870'; ctx.beginPath(); ctx.roundRect(-11*sc,-28*sc,22*sc,12*sc,2*sc); ctx.fill(); ctx.stroke();
  [[18,3.5],[14,3],[10,2.5]].forEach(([w,h],i)=>{
    const ry=-34*sc-i*7*sc;
    ctx.fillStyle=['#c85030','#d86040','#e07050'][i]; ctx.strokeStyle='#9a3020'; ctx.lineWidth=sc*.8;
    ctx.beginPath(); ctx.moveTo(-w*sc,ry+h*sc); ctx.lineTo(0,ry-h*sc); ctx.lineTo(w*sc,ry+h*sc); ctx.closePath(); ctx.fill(); ctx.stroke();
  });
  ctx.strokeStyle='#9a3020'; ctx.lineWidth=1.5*sc;
  ctx.beginPath(); ctx.moveTo(0,-55*sc); ctx.lineTo(0,-62*sc); ctx.stroke();
  ctx.fillStyle='#ffcc44'; ctx.beginPath(); ctx.arc(0,-63*sc,2.5*sc,0,Math.PI*2); ctx.fill();
  ctx.fillStyle='rgba(100,60,20,.5)';
  [[-7,-10],[0,-10],[7,-10],[-7,0],[7,0]].forEach(([wx,wy])=>{ ctx.beginPath(); ctx.roundRect(wx*sc-2.5*sc,wy*sc-3.5*sc,5*sc,6*sc,1*sc); ctx.fill(); });
  ctx.fillStyle='#e03020'; ctx.beginPath(); ctx.moveTo(0,-63*sc); ctx.lineTo(8*sc,-60*sc); ctx.lineTo(0,-57*sc); ctx.closePath(); ctx.fill();
  ctx.fillStyle='rgba(255,255,255,.9)'; ctx.strokeStyle='rgba(100,60,20,.6)'; ctx.lineWidth=2.5*sc;
  ctx.font=`bold ${9*sc}px Nunito,sans-serif`; ctx.textAlign='center';
  ctx.strokeText('赤崁樓',0,22*sc); ctx.fillText('赤崁樓',0,22*sc);
  ctx.font=`${7*sc}px Nunito,sans-serif`; ctx.fillStyle='rgba(80,40,10,.85)'; ctx.fillText('Chihkan Tower',0,31*sc);
  if(flood>0){ ctx.fillStyle=`rgba(109,200,232,${flood*.45})`; ctx.beginPath(); ctx.roundRect(-22*sc,14*sc-(flood*28*sc),44*sc,flood*28*sc+10*sc,2*sc); ctx.fill(); }
  ctx.restore();
}

function drawTaipei101(ctx,x,y,sc,wl,t){
  ctx.save(); ctx.translate(x,y);
  const flood=Math.min(1,wl/80), bob=Math.sin(t*1.2)*1.5*sc;
  ctx.translate(0,bob);
  ctx.fillStyle='rgba(0,0,0,0.10)'; ctx.beginPath(); ctx.ellipse(0,6*sc,16*sc,4*sc,0,0,Math.PI*2); ctx.fill();
  ctx.fillStyle='#4a7a5a'; ctx.strokeStyle='#2a5a3a'; ctx.lineWidth=sc*.7;
  ctx.beginPath(); ctx.roundRect(-16*sc,2*sc,32*sc,8*sc,1.5*sc); ctx.fill(); ctx.stroke();
  for(let i=0;i<8;i++){
    const sw=(14-i*1.2)*sc, sh=7*sc, sy=2*sc-(i+1)*sh;
    const g=ctx.createLinearGradient(-sw,0,sw,0);
    g.addColorStop(0,'#3a6a8a'); g.addColorStop(.4,'#5a9abf'); g.addColorStop(1,'#3a6a8a');
    ctx.fillStyle=g; ctx.strokeStyle='#2a5a7a'; ctx.lineWidth=sc*.5;
    ctx.beginPath(); ctx.roundRect(-sw,sy,sw*2,sh+sc,1*sc); ctx.fill(); ctx.stroke();
    ctx.fillStyle='#7abedd'; ctx.beginPath(); ctx.roundRect(-sw,sy,sw*2,2*sc,1*sc); ctx.fill();
    ctx.fillStyle='rgba(200,240,255,.45)';
    for(let w=-sw+3*sc;w<sw-3*sc;w+=4*sc){ ctx.beginPath(); ctx.rect(w,sy+2.5*sc,2*sc,3*sc); ctx.fill(); }
  }
  ctx.strokeStyle='#ccddee'; ctx.lineWidth=2.5*sc;
  const topY=2*sc-8*7*sc;
  ctx.beginPath(); ctx.moveTo(0,topY); ctx.lineTo(0,topY-22*sc); ctx.stroke();
  [topY-10*sc,topY-16*sc,topY-22*sc].forEach((ay,i)=>{
    ctx.fillStyle=['#ffcc44','#ff9922','#ff6644'][i]; ctx.beginPath(); ctx.arc(0,ay,(2.2-i*.4)*sc,0,Math.PI*2); ctx.fill();
  });
  ctx.fillStyle='rgba(255,220,100,.8)'; ctx.beginPath(); ctx.arc(0,topY,4*sc,0,Math.PI*2); ctx.fill();
  ctx.fillStyle='rgba(255,255,255,.9)'; ctx.strokeStyle='rgba(30,80,120,.6)'; ctx.lineWidth=2.5*sc;
  ctx.font=`bold ${9*sc}px Nunito,sans-serif`; ctx.textAlign='center';
  ctx.strokeText('台北101',0,18*sc); ctx.fillText('台北101',0,18*sc);
  ctx.font=`${7*sc}px Nunito,sans-serif`; ctx.fillStyle='rgba(30,60,100,.85)'; ctx.fillText('Taipei 101',0,27*sc);
  if(flood>0){ ctx.fillStyle=`rgba(109,200,232,${flood*.4})`; ctx.beginPath(); ctx.roundRect(-16*sc,2*sc-(flood*42*sc),32*sc,flood*42*sc+8*sc,2*sc); ctx.fill(); }
  ctx.restore();
}

function drawDragonTigerPagoda(ctx,x,y,sc,wl,t){
  ctx.save(); ctx.translate(x,y);
  const flood=Math.min(1,wl/80), bob=Math.sin(t*1.3)*2*sc;
  ctx.translate(0,bob);
  ctx.fillStyle='rgba(109,200,232,.3)'; ctx.beginPath(); ctx.ellipse(0,12*sc,40*sc,9*sc,0,0,Math.PI*2); ctx.fill();
  function drawPagoda(px,col1,col2){
    for(let i=0;i<7;i++){
      const pw=(4-i*.45)*8*sc, ph=6*sc, py=-6*sc-i*7.5*sc;
      ctx.fillStyle=i%2===0?col1:col2; ctx.strokeStyle='rgba(0,0,0,.2)'; ctx.lineWidth=sc*.5;
      ctx.beginPath(); ctx.roundRect(px-pw/2,py,pw,ph,1*sc); ctx.fill(); ctx.stroke();
      ctx.fillStyle=col2;
      ctx.beginPath(); ctx.moveTo(px-pw/2-2*sc,py); ctx.lineTo(px,py-2.5*sc); ctx.lineTo(px+pw/2+2*sc,py); ctx.lineTo(px+pw/2,py+1.5*sc); ctx.lineTo(px-pw/2,py+1.5*sc); ctx.closePath(); ctx.fill();
    }
    const sy=-6*sc-7*7.5*sc;
    ctx.strokeStyle=col1; ctx.lineWidth=1.5*sc; ctx.beginPath(); ctx.moveTo(px,sy); ctx.lineTo(px,sy-10*sc); ctx.stroke();
    ctx.fillStyle='#ffcc44'; ctx.beginPath(); ctx.arc(px,sy-11*sc,2.5*sc,0,Math.PI*2); ctx.fill();
  }
  drawPagoda(-24*sc,'#c83030','#e85050');
  drawPagoda(24*sc,'#1a6aaa','#3a8acc');
  // Dragon
  ctx.save(); ctx.translate(-36*sc,4*sc); ctx.rotate(Math.sin(t*2)*.07);
  ctx.fillStyle='#3a9a40'; ctx.strokeStyle='#1a6a20'; ctx.lineWidth=sc*.7;
  ctx.beginPath(); ctx.ellipse(0,0,11*sc,7*sc,-.3,0,Math.PI*2); ctx.fill(); ctx.stroke();
  ctx.fillStyle='#4ab050'; ctx.beginPath(); ctx.ellipse(-6*sc,-3*sc,8*sc,6*sc,-.4,0,Math.PI*2); ctx.fill(); ctx.stroke();
  ctx.fillStyle='#ffcc00'; ctx.beginPath(); ctx.arc(-8*sc,-5*sc,2.5*sc,0,Math.PI*2); ctx.fill();
  ctx.fillStyle='#222'; ctx.beginPath(); ctx.arc(-8.5*sc,-5.5*sc,1.2*sc,0,Math.PI*2); ctx.fill();
  ctx.globalAlpha=.65+Math.sin(t*4)*.2; ctx.fillStyle='#ff8822'; ctx.beginPath(); ctx.arc(-16*sc,0,4*sc,0,Math.PI*2); ctx.fill();
  ctx.fillStyle='#ffcc44'; ctx.beginPath(); ctx.arc(-17*sc,-1.5*sc,2.5*sc,0,Math.PI*2); ctx.fill(); ctx.globalAlpha=1;
  ctx.restore();
  // Tiger
  ctx.save(); ctx.translate(36*sc,4*sc); ctx.rotate(-Math.sin(t*2.2)*.07);
  ctx.fillStyle='#e87020'; ctx.strokeStyle='#a84010'; ctx.lineWidth=sc*.7;
  ctx.beginPath(); ctx.ellipse(0,0,11*sc,7*sc,.3,0,Math.PI*2); ctx.fill(); ctx.stroke();
  ctx.fillStyle='#f09030'; ctx.beginPath(); ctx.ellipse(6*sc,-3*sc,8*sc,6*sc,.4,0,Math.PI*2); ctx.fill(); ctx.stroke();
  ctx.strokeStyle='rgba(150,60,0,.5)'; ctx.lineWidth=sc*.8;
  [[3,-6,5,-2],[5,-5,7,-1],[7,-6,8,-3]].forEach(([x1,y1,x2,y2])=>{ ctx.beginPath(); ctx.moveTo(x1*sc,y1*sc); ctx.lineTo(x2*sc,y2*sc); ctx.stroke(); });
  ctx.fillStyle='#ffcc00'; ctx.beginPath(); ctx.arc(8*sc,-5*sc,2.5*sc,0,Math.PI*2); ctx.fill();
  ctx.fillStyle='#222'; ctx.beginPath(); ctx.arc(8.5*sc,-5.5*sc,1.2*sc,0,Math.PI*2); ctx.fill();
  ctx.restore();
  ctx.fillStyle='rgba(200,170,100,.65)'; ctx.beginPath(); ctx.roundRect(-38*sc,5*sc,76*sc,4*sc,2*sc); ctx.fill();
  ctx.fillStyle='rgba(255,255,255,.9)'; ctx.strokeStyle='rgba(150,50,20,.6)'; ctx.lineWidth=2.5*sc;
  ctx.font=`bold ${9*sc}px Nunito,sans-serif`; ctx.textAlign='center';
  ctx.strokeText('龍虎塔',0,22*sc); ctx.fillText('龍虎塔',0,22*sc);
  ctx.font=`${7*sc}px Nunito,sans-serif`; ctx.fillStyle='rgba(150,50,0,.85)'; ctx.fillText('Dragon & Tiger Pagodas',0,31*sc);
  if(flood>0){ ctx.fillStyle=`rgba(109,200,232,${flood*.4})`; ctx.beginPath(); ctx.ellipse(0,12*sc,40*sc,9+(flood*22)*sc,0,0,Math.PI*2); ctx.fill(); }
  ctx.restore();
}

function drawTarokoGorge(ctx,x,y,sc,wl,t){
  ctx.save(); ctx.translate(x,y);
  const flood=Math.min(1,wl/80), bob=Math.sin(t*.8)*sc;
  ctx.translate(0,bob);
  ctx.fillStyle='rgba(0,0,0,0.09)'; ctx.beginPath(); ctx.ellipse(0,8*sc,34*sc,6*sc,0,0,Math.PI*2); ctx.fill();
  // Left cliff
  const lg=ctx.createLinearGradient(-30*sc,0,0,0);
  lg.addColorStop(0,'#6a7a8a'); lg.addColorStop(.7,'#8a9aaa'); lg.addColorStop(1,'#aabbc8');
  ctx.fillStyle=lg; ctx.strokeStyle='rgba(60,70,80,.4)'; ctx.lineWidth=sc*.6;
  ctx.beginPath(); ctx.moveTo(-32*sc,8*sc); ctx.lineTo(-32*sc,-28*sc); ctx.bezierCurveTo(-28*sc,-38*sc,-20*sc,-42*sc,-14*sc,-32*sc); ctx.bezierCurveTo(-12*sc,-24*sc,-10*sc,-16*sc,-8*sc,8*sc); ctx.closePath(); ctx.fill(); ctx.stroke();
  ctx.fillStyle='rgba(235,248,255,.7)'; ctx.beginPath(); ctx.moveTo(-28*sc,-30*sc); ctx.bezierCurveTo(-24*sc,-42*sc,-18*sc,-46*sc,-14*sc,-36*sc); ctx.bezierCurveTo(-16*sc,-30*sc,-22*sc,-28*sc,-28*sc,-30*sc); ctx.closePath(); ctx.fill();
  // Right cliff
  const rg=ctx.createLinearGradient(0,0,30*sc,0);
  rg.addColorStop(0,'#aabbc8'); rg.addColorStop(.3,'#8a9aaa'); rg.addColorStop(1,'#6a7a8a');
  ctx.fillStyle=rg; ctx.beginPath(); ctx.moveTo(32*sc,8*sc); ctx.lineTo(32*sc,-24*sc); ctx.bezierCurveTo(28*sc,-36*sc,20*sc,-40*sc,14*sc,-30*sc); ctx.bezierCurveTo(12*sc,-22*sc,10*sc,-12*sc,8*sc,8*sc); ctx.closePath(); ctx.fill(); ctx.stroke();
  ctx.fillStyle='rgba(235,248,255,.6)'; ctx.beginPath(); ctx.moveTo(28*sc,-26*sc); ctx.bezierCurveTo(24*sc,-40*sc,18*sc,-44*sc,14*sc,-34*sc); ctx.bezierCurveTo(16*sc,-28*sc,22*sc,-26*sc,28*sc,-26*sc); ctx.closePath(); ctx.fill();
  // River
  const gg=ctx.createLinearGradient(-9*sc,0,9*sc,0);
  gg.addColorStop(0,'rgba(109,200,232,.5)'); gg.addColorStop(.5,'rgba(160,228,255,.85)'); gg.addColorStop(1,'rgba(109,200,232,.5)');
  ctx.fillStyle=gg; ctx.beginPath(); ctx.roundRect(-9*sc,0,18*sc,8*sc,3*sc); ctx.fill();
  ctx.strokeStyle='rgba(255,255,255,.65)'; ctx.lineWidth=sc*.7;
  for(let i=0;i<4;i++){ const wx=-6*sc+i*3.5*sc+Math.sin(t*2+i)*.8*sc; ctx.beginPath(); ctx.arc(wx,3.5*sc,1.5*sc,Math.PI,0); ctx.stroke(); }
  // Waterfall
  ctx.strokeStyle='rgba(180,230,255,.75)'; ctx.lineWidth=2*sc; ctx.setLineDash([2*sc,2*sc]);
  ctx.beginPath(); ctx.moveTo(-8*sc,-8*sc); ctx.lineTo(-7*sc,2*sc); ctx.stroke(); ctx.setLineDash([]);
  ctx.fillStyle='rgba(200,240,255,.6)'; ctx.beginPath(); ctx.ellipse(-7*sc,3.5*sc,3.5*sc,2*sc,0,0,Math.PI*2); ctx.fill();
  // Trees
  [[-22,4],[-18,3],[18,3],[22,4]].forEach(([tx,ty])=>{
    ctx.fillStyle='#4a8a3a'; ctx.beginPath(); ctx.moveTo(tx*sc,ty*sc); ctx.lineTo((tx-3)*sc,(ty-8)*sc); ctx.lineTo((tx+3)*sc,(ty-8)*sc); ctx.closePath(); ctx.fill();
    ctx.fillStyle='#3a7a2a'; ctx.beginPath(); ctx.moveTo(tx*sc,(ty-5)*sc); ctx.lineTo((tx-2.5)*sc,(ty-13)*sc); ctx.lineTo((tx+2.5)*sc,(ty-13)*sc); ctx.closePath(); ctx.fill();
  });
  // Arch
  ctx.strokeStyle='rgba(120,140,160,.55)'; ctx.lineWidth=sc*1.5;
  ctx.beginPath(); ctx.arc(0,-3*sc,10*sc,Math.PI,0); ctx.stroke();
  ctx.fillStyle='rgba(255,255,255,.9)'; ctx.strokeStyle='rgba(60,80,100,.6)'; ctx.lineWidth=2.5*sc;
  ctx.font=`bold ${9*sc}px Nunito,sans-serif`; ctx.textAlign='center';
  ctx.strokeText('太魯閣',0,22*sc); ctx.fillText('太魯閣',0,22*sc);
  ctx.font=`${7*sc}px Nunito,sans-serif`; ctx.fillStyle='rgba(40,60,90,.85)'; ctx.fillText('Taroko Gorge',0,31*sc);
  if(flood>0){ ctx.fillStyle=`rgba(109,200,232,${flood*.5})`; ctx.beginPath(); ctx.roundRect(-32*sc,8*sc-(flood*20*sc),64*sc,flood*20*sc+8*sc,3*sc); ctx.fill(); }
  ctx.restore();
}

function drawLandmark(ctx,wl,t){
  const lx=simW*.72, ly=simH*.52, sc=Math.min(simW,simH)/700;
  if(landmarkIntro<1) landmarkIntro=Math.min(1,landmarkIntro+0.045);
  const ease=1-Math.pow(1-landmarkIntro,3);
  ctx.save(); ctx.translate(lx,ly); ctx.scale(ease,ease); ctx.translate(-lx,-ly);
  // Glow halo behind landmark
  const halo=ctx.createRadialGradient(lx,ly,10,lx,ly,55*sc);
  halo.addColorStop(0,`rgba(109,200,232,${0.13+Math.sin(t*1.8)*.05})`);
  halo.addColorStop(1,'rgba(109,200,232,0)');
  ctx.fillStyle=halo; ctx.beginPath(); ctx.arc(lx,ly,55*sc,0,Math.PI*2); ctx.fill();
  if(currentLandmark==='tainan'){
    drawChihkanTower(ctx,lx-28*sc,ly,sc,wl,t);
    drawNCKU(ctx,lx+32*sc,ly+8*sc,sc*0.72,wl,t);
  } else if(currentLandmark==='taipei')  drawTaipei101(ctx,lx,ly,sc,wl,t);
  else if(currentLandmark==='kaohsiung') drawDragonTigerPagoda(ctx,lx,ly,sc,wl,t);
  else if(currentLandmark==='hualien'){
    drawTarokoGorge(ctx,lx-22*sc,ly-8*sc,sc,wl,t);
    drawHualienBeach(ctx,lx+38*sc,ly+10*sc,sc*0.75,wl,t);
  }
  ctx.restore();
}

// ── NCKU (National Cheng Kung University, Tainan) ──
function drawNCKU(ctx,x,y,sc,wl,t){
  ctx.save(); ctx.translate(x,y);
  const flood=Math.min(1,wl/80), bob=Math.sin(t*1.6+1)*1.5*sc;
  ctx.translate(0,bob);
  // Shadow
  ctx.fillStyle='rgba(0,0,0,0.08)'; ctx.beginPath(); ctx.ellipse(0,6*sc,20*sc,4*sc,0,0,Math.PI*2); ctx.fill();
  // Main building - red brick colonial style (admin building)
  const bg=ctx.createLinearGradient(-16*sc,-20*sc,16*sc,6*sc);
  bg.addColorStop(0,'#c84020'); bg.addColorStop(0.5,'#e05030'); bg.addColorStop(1,'#b83018');
  ctx.fillStyle=bg; ctx.strokeStyle='#8a2010'; ctx.lineWidth=sc*.6;
  ctx.beginPath(); ctx.roundRect(-16*sc,-20*sc,32*sc,26*sc,1.5*sc); ctx.fill(); ctx.stroke();
  // Windows grid
  ctx.fillStyle='rgba(200,230,255,.55)';
  [[-9,-14],[0,-14],[9,-14],[-9,-5],[0,-5],[9,-5]].forEach(([wx,wy])=>{
    ctx.beginPath(); ctx.roundRect(wx*sc-2.5*sc,wy*sc-3*sc,5*sc,5.5*sc,0.8*sc); ctx.fill();
  });
  // White columns (portico)
  [-8,-3,2,7].forEach(cx2=>{
    ctx.fillStyle='rgba(255,255,255,.85)';
    ctx.beginPath(); ctx.roundRect(cx2*sc,-20*sc,2.8*sc,7*sc,0.5*sc); ctx.fill();
  });
  // Arched entrance
  ctx.fillStyle='rgba(40,20,10,.7)';
  ctx.beginPath(); ctx.arc(0,-13*sc,4*sc,Math.PI,0); ctx.lineTo(4*sc,-13*sc); ctx.lineTo(4*sc,-6*sc); ctx.lineTo(-4*sc,-6*sc); ctx.closePath(); ctx.fill();
  // Roof / pediment
  ctx.fillStyle='#c84020'; ctx.strokeStyle='#8a2010';
  ctx.beginPath(); ctx.moveTo(-18*sc,-20*sc); ctx.lineTo(0,-30*sc); ctx.lineTo(18*sc,-20*sc); ctx.closePath(); ctx.fill(); ctx.stroke();
  // Flag on roof
  ctx.strokeStyle='#888'; ctx.lineWidth=sc*.8;
  ctx.beginPath(); ctx.moveTo(0,-30*sc); ctx.lineTo(0,-39*sc); ctx.stroke();
  // Taiwanese flag (simple blue rect + circle)
  ctx.save(); ctx.translate(0,-39*sc);
  const flagWave=Math.sin(t*3)*2*sc;
  ctx.fillStyle='#003288';
  ctx.beginPath(); ctx.moveTo(0,0); ctx.lineTo(12*sc,flagWave); ctx.lineTo(12*sc,6*sc+flagWave*.5); ctx.lineTo(0,6*sc); ctx.closePath(); ctx.fill();
  ctx.fillStyle='#cc0000';
  ctx.beginPath(); ctx.moveTo(0,3*sc); ctx.lineTo(12*sc,3*sc+flagWave); ctx.lineTo(12*sc,6*sc+flagWave*.5); ctx.lineTo(0,6*sc); ctx.closePath(); ctx.fill();
  ctx.fillStyle='white'; ctx.beginPath(); ctx.arc(5*sc,3*sc+flagWave*.4,1.8*sc,0,Math.PI*2); ctx.fill();
  ctx.restore();
  // Side wings
  [-1,1].forEach(side=>{
    ctx.fillStyle='#d04828'; ctx.strokeStyle='#8a2010'; ctx.lineWidth=sc*.5;
    ctx.beginPath(); ctx.roundRect(side*16*sc,-14*sc,side*8*sc,20*sc,1*sc); ctx.fill(); ctx.stroke();
    ctx.fillStyle='rgba(200,230,255,.4)';
    [[-5],[1],[-5]].forEach(([_],ri)=>{
      ctx.beginPath(); ctx.roundRect((side*17+side*2)*sc,(-12+ri*5)*sc,3.5*sc,4*sc,0.6*sc); ctx.fill();
    });
  });
  // Ground
  ctx.fillStyle='rgba(180,220,160,.6)';
  ctx.beginPath(); ctx.roundRect(-20*sc,5*sc,40*sc,3*sc,1.5*sc); ctx.fill();
  // Label
  ctx.fillStyle='rgba(255,255,255,.92)'; ctx.strokeStyle='rgba(120,40,10,.6)'; ctx.lineWidth=2*sc;
  ctx.font=`bold ${8*sc}px Nunito,sans-serif`; ctx.textAlign='center';
  ctx.strokeText('成大 NCKU',0,17*sc); ctx.fillText('成大 NCKU',0,17*sc);
  ctx.font=`${6.5*sc}px Nunito,sans-serif`; ctx.fillStyle='rgba(80,30,10,.8)';
  ctx.fillText('Cheng Kung Univ.',0,25*sc);
  // Flood
  if(flood>0){ ctx.fillStyle=`rgba(109,200,232,${flood*.4})`; ctx.beginPath(); ctx.roundRect(-20*sc,5*sc-(flood*24*sc),40*sc,flood*24*sc+4*sc,1.5*sc); ctx.fill(); }
  ctx.restore();
}

// ── HUALIEN BEACH ──
function drawHualienBeach(ctx,x,y,sc,wl,t){
  ctx.save(); ctx.translate(x,y);
  const flood=Math.min(1,wl/80), bob=Math.sin(t*1.1+2)*sc;
  ctx.translate(0,bob);
  // Shadow
  ctx.fillStyle='rgba(0,0,0,0.07)'; ctx.beginPath(); ctx.ellipse(0,8*sc,22*sc,4*sc,0,0,Math.PI*2); ctx.fill();
  // Sky gradient
  const sky=ctx.createLinearGradient(0,-22*sc,0,0);
  sky.addColorStop(0,'rgba(135,206,250,.55)'); sky.addColorStop(1,'rgba(200,240,255,.0)');
  ctx.fillStyle=sky; ctx.beginPath(); ctx.roundRect(-22*sc,-22*sc,44*sc,22*sc,3*sc); ctx.fill();
  // Ocean
  const oc=ctx.createLinearGradient(0,0,0,8*sc);
  oc.addColorStop(0,`rgba(32,100,200,${0.55+flood*.2})`);
  oc.addColorStop(1,`rgba(58,155,191,${0.45+flood*.2})`);
  ctx.fillStyle=oc; ctx.beginPath(); ctx.roundRect(-22*sc,0,44*sc,8*sc,1*sc); ctx.fill();
  // Animated waves on ocean surface
  ctx.strokeStyle='rgba(200,240,255,.65)'; ctx.lineWidth=sc*.8;
  for(let wi2=0;wi2<3;wi2++){
    const wx=-16*sc+wi2*10*sc+Math.sin(t*2.2+wi2)*3*sc;
    ctx.beginPath(); ctx.arc(wx,2.5*sc,5*sc,Math.PI+0.3,Math.PI*2-0.3); ctx.stroke();
  }
  // Sandy beach
  const sand=ctx.createLinearGradient(0,0,0,6*sc);
  sand.addColorStop(0,'#f5e6a0'); sand.addColorStop(1,'#e8d080');
  ctx.fillStyle=sand; ctx.beginPath();
  ctx.moveTo(-22*sc,6*sc); ctx.bezierCurveTo(-15*sc,4*sc,15*sc,5*sc,22*sc,6*sc);
  ctx.lineTo(22*sc,8*sc); ctx.lineTo(-22*sc,8*sc); ctx.closePath(); ctx.fill();
  // Palm tree
  ctx.save(); ctx.translate(-12*sc,0);
  const sway=Math.sin(t*1.3)*0.06;
  ctx.strokeStyle='#a07040'; ctx.lineWidth=2.5*sc;
  ctx.beginPath(); ctx.moveTo(0,6*sc); ctx.bezierCurveTo(0+sway*20*sc,0,2*sc,-6*sc,3*sc,-13*sc); ctx.stroke();
  // Leaves
  const leafAngs=[0,0.7,1.4,2.1,2.8,3.5];
  leafAngs.forEach((la,li)=>{
    ctx.fillStyle=li%2?'#4a8a2a':'#3a7a20';
    ctx.save(); ctx.translate(3*sc,-13*sc); ctx.rotate(la+sway*2);
    ctx.beginPath(); ctx.ellipse(6*sc,0,7*sc,2.5*sc,-0.2,0,Math.PI*2); ctx.fill();
    ctx.restore();
  });
  ctx.restore();
  // Lighthouse
  ctx.save(); ctx.translate(14*sc,0);
  ctx.fillStyle='#f0f0f0'; ctx.strokeStyle='#cc3333'; ctx.lineWidth=sc*.8;
  ctx.beginPath(); ctx.roundRect(-3*sc,-14*sc,6*sc,14*sc,0.5*sc); ctx.fill(); ctx.stroke();
  // Stripes
  [0,1,2].forEach(i=>{ if(i%2){ ctx.fillStyle='#cc3333'; ctx.beginPath(); ctx.roundRect(-3*sc,-14*sc+i*4.5*sc,6*sc,4.5*sc,0); ctx.fill(); } });
  // Light
  ctx.fillStyle=`rgba(255,255,180,${0.7+Math.sin(t*4)*.3})`;
  ctx.beginPath(); ctx.arc(0,-15.5*sc,2.5*sc,0,Math.PI*2); ctx.fill();
  // Beam
  ctx.save(); ctx.translate(0,-15.5*sc); ctx.rotate(t*1.5);
  const beam=ctx.createLinearGradient(0,0,28*sc,0);
  beam.addColorStop(0,`rgba(255,255,180,${0.5+Math.sin(t*4)*.2})`);
  beam.addColorStop(1,'rgba(255,255,180,0)');
  ctx.fillStyle=beam;
  ctx.beginPath(); ctx.moveTo(0,0); ctx.lineTo(28*sc,-5*sc); ctx.lineTo(28*sc,5*sc); ctx.closePath(); ctx.fill();
  ctx.restore();
  ctx.restore();
  // Seagull (animated)
  const sgx = Math.sin(t*0.9)*15*sc;
  const sgy = -12*sc + Math.sin(t*1.8)*3*sc;
  ctx.fillStyle='rgba(80,80,80,.7)'; ctx.font=`${7*sc}px serif`; ctx.textAlign='center';
  ctx.fillText('🕊',sgx,sgy);
  // Label
  ctx.fillStyle='rgba(255,255,255,.92)'; ctx.strokeStyle='rgba(20,60,120,.5)'; ctx.lineWidth=2*sc;
  ctx.font=`bold ${8*sc}px Nunito,sans-serif`; ctx.textAlign='center';
  ctx.strokeText('花蓮海灘',0,19*sc); ctx.fillText('花蓮海灘',0,19*sc);
  ctx.font=`${6.5*sc}px Nunito,sans-serif`; ctx.fillStyle='rgba(20,60,130,.8)';
  ctx.fillText('Hualien Beach',0,27*sc);
  // Flood
  if(flood>0){ ctx.fillStyle=`rgba(58,155,191,${flood*.5})`; ctx.beginPath(); ctx.roundRect(-22*sc,6*sc-(flood*18*sc),44*sc,flood*18*sc+4*sc,1.5*sc); ctx.fill(); }
  ctx.restore();
}

// ── LOCATION SWITCHER ──
function switchLoc(el,name,country){
  document.querySelectorAll('.lpill').forEach(p=>p.classList.remove('active'));
  el.classList.add('active'); curLoc=name; curCountry=country||'Taiwan';
  document.getElementById('loc-name').textContent=name;
  document.getElementById('bs-loc').textContent=name+', '+curCountry;
  const lmap={'Tainan Basin':'tainan','Taipei Metro':'taipei','Kaohsiung Port':'kaohsiung','Hualien Coast':'hualien'};
  currentLandmark=lmap[name]||'tainan';
  currentDEMKey=lmap[name]||'tainan';
  landmarkIntro=0;
  initMapCars(currentDEMKey);
  buildHeightmap(currentDEMKey);
  // Update coordinate display
  fetchLiveWeather(currentDEMKey);
  const cityData=REAL_DEM[currentDEMKey];
  if(cityData&&document.getElementById('bs-coords')){
    const la=cityData.lat_range, lo2=cityData.lon_range;
    document.getElementById('bs-coords').textContent=`${la[0]}–${la[1]}°N, ${lo2[0]}–${lo2[1]}°E`;
  }
}


