// Typhoon eye canvas overlay
let typhTrackOverlay = [];   // {x,y,alpha} screen coords of track dots
let typhEyePos = null;       // {x,y,r,windR} current eye position
let typhEyeAngle = 0;

function latLonToCanvas(lat, lon) {
  // Map lat/lon to canvas xy based on current city's geographic bounds
  const city = REAL_DEM[currentDEMKey];
  if (!city) return null;
  const [latMin, latMax] = city.lat_range;
  const [lonMin, lonMax] = city.lon_range;
  // Expand view to include typhoon track (which may be outside city bounds)
  const latRange = Math.max(latMax - latMin, 8);
  const lonRange = Math.max(lonMax - lonMin, 10);
  const latCen = (latMin + latMax) / 2;
  const lonCen = (lonMin + lonMax) / 2;
  const nx = (lon - (lonCen - lonRange*0.5)) / lonRange;
  const ny = 1 - (lat - (latCen - latRange*0.5)) / latRange;
  return { x: nx * simW, y: ny * simH * 0.85 + simH * 0.05 };
}

// Replay state (declared earlier, near top of script)

function selectTyphoon(key, el) {
  document.querySelectorAll('.typh-item').forEach(i => i.classList.remove('active'));
  if (el) el.classList.add('active');
  selectedTyphoon = key;
  replayStep = 0;
  replayPlaying = false;
  stopTyphoonReplay();
  // Clear progress bars
  document.querySelectorAll('.typh-prog-fill').forEach(b => b.style.width = '0%');
  document.getElementById('replay-time').innerHTML =
    `<span>${TYPHOON_DATA[key].name}</span> selected · Press ▶ Play`;
  // Switch to most-impacted city
  const impact = TYPHOON_DATA[key].cityImpact;
  const bestCity = Object.entries(impact).sort((a,b)=>b[1]-a[1])[0][0];
  const cityNames = {tainan:'Tainan Basin',taipei:'Taipei Metro',kaohsiung:'Kaohsiung Port',hualien:'Hualien Coast'};
  const pill = [...document.querySelectorAll('.lpill')].find(p=>p.textContent.includes(cityNames[bestCity].split(' ')[0]));
  if (pill) switchLoc(pill, cityNames[bestCity], 'Taiwan');
  // Build track overlay for this city view
  buildTrackOverlay(key);
}

function buildTrackOverlay(key) {
  typhTrackOverlay = [];
  const td = TYPHOON_DATA[key];
  td.track.forEach((step, i) => {
    const p = latLonToCanvas(step[0], step[1]);
    if (p) typhTrackOverlay.push({ x:p.x, y:p.y, alpha: i/td.track.length, wind:step[2] });
  });
}

function toggleTyphoonReplay() {
  if (!selectedTyphoon) {
    showDEMToast('Select a typhoon first!', '', ''); return;
  }
  if (replayPlaying) {
    // Pause
    replayPlaying = false;
    clearInterval(replayInterval); replayInterval = null;
    document.getElementById('typh-play-btn').textContent = '▶ Resume';
  } else {
    // Play / Resume
    if (replayStep >= TYPHOON_DATA[selectedTyphoon].track.length - 1) replayStep = 0;
    replayPlaying = true;
    document.getElementById('typh-play-btn').textContent = '⏸ Pause';
    const msPerStep = Math.max(120, 900 / replaySpeed);
    replayInterval = setInterval(advanceReplay, msPerStep);
    // switch off regular typhoon mode
    typhMode = false; autoRun = false;
  }
}

function advanceReplay() {
  if (!selectedTyphoon) return;
  const td = TYPHOON_DATA[selectedTyphoon];
  if (replayStep >= td.track.length) {
    stopTyphoonReplay(); return;
  }
  const step = td.track[replayStep];
  const [lat, lon, windKmh, rainPct, pressure] = step;
  // Update sim sliders based on typhoon step data
  const impact = td.cityImpact[currentDEMKey] / 100;
  const wl = Math.min(94, rainPct * impact * 0.9);
  const wi = Math.min(100, 25 + windKmh * 0.45 * impact);
  const rr = Math.min(100, rainPct * impact);
  const ws = Math.min(100, windKmh * 0.6 * impact);

  document.getElementById('s-wl').value = wl;
  document.getElementById('s-wi').value = wi;
  document.getElementById('s-rr').value = rr;
  document.getElementById('s-ws').value = ws;
  document.getElementById('s-tmp').value = Math.max(15, 28 - rainPct * 0.12);
  updateAll();

  // Update typhoon eye on canvas
  const eyePos = latLonToCanvas(lat, lon);
  if (eyePos) {
    typhEyePos = {
      x: eyePos.x, y: eyePos.y,
      r: 18 + windKmh * 0.12,   // eye radius scales with intensity
      windR: 40 + windKmh * 0.35,
      color: td.color,
      wind: windKmh,
      pressure: pressure,
    };
  }

  // Progress bar
  const pct = (replayStep / (td.track.length-1)) * 100;
  const bar = document.getElementById('tp-' + selectedTyphoon);
  if (bar) bar.style.width = pct + '%';

  // Time display
  const stepHours = replayStep * 6;
  const day = Math.floor(stepHours / 24) + 1;
  const hour = stepHours % 24;
  document.getElementById('replay-time').innerHTML =
    `🌀 Day ${day} &nbsp;|&nbsp; <span>${String(hour).padStart(2,'0')}:00 TWN</span>
     &nbsp;|&nbsp; 💨 ${windKmh} km/h &nbsp;|&nbsp; 📉 ${pressure} hPa`;

  replayStep++;
}

function stopTyphoonReplay() {
  replayPlaying = false;
  if (replayInterval) { clearInterval(replayInterval); replayInterval = null; }
  document.getElementById('typh-play-btn').textContent = '▶ Play';
  typhEyePos = null; replayStep = 0;
  // Reset sliders gently
  ['s-wl','s-rr'].forEach(id => { document.getElementById(id).value = 0; });
  updateAll();
  if (selectedTyphoon) {
    const bar = document.getElementById('tp-' + selectedTyphoon);
    if (bar) bar.style.width = '0%';
  }
  document.getElementById('replay-time').innerHTML = selectedTyphoon
    ? `<span>${TYPHOON_DATA[selectedTyphoon].name}</span> · Press ▶ to replay`
    : 'Select a typhoon to replay ↑';
}

function cycleReplaySpeed() {
  const speeds = [1, 3, 8];
  const labels = ['1× Speed', '3× Fast', '8× Ultra'];
  replaySpeed = speeds[(speeds.indexOf(replaySpeed)+1) % speeds.length];
  document.getElementById('typh-speed-btn').textContent = labels[speeds.indexOf(replaySpeed)];
  // Restart interval at new speed if playing
  if (replayPlaying && replayInterval) {
    clearInterval(replayInterval);
    replayInterval = setInterval(advanceReplay, Math.max(120, 900/replaySpeed));
  }
}

// ── TYPHOON EYE DRAWING ── called inside renderSim
function drawTyphoonEye(ctx, t) {
  if (!typhEyePos) return;
  const {x, y, r, windR, color, wind} = typhEyePos;
  ctx.save();
  typhEyeAngle += 0.018 * (wind / 100);

  // Outer spiral bands (3 arms)
  for (let arm = 0; arm < 3; arm++) {
    const armAngle = typhEyeAngle + arm * (Math.PI * 2 / 3);
    ctx.save();
    ctx.translate(x, y);
    ctx.rotate(armAngle);
    for (let i = 0; i < 18; i++) {
      const frac = i / 18;
      const sr = windR * (0.3 + frac * 0.7);
      const sx = sr * Math.cos(frac * Math.PI * 1.4);
      const sy = sr * Math.sin(frac * Math.PI * 1.4) * 0.55;
      const alpha = (1 - frac) * 0.22;
      const sz = 3 + frac * 9;
      ctx.fillStyle = `rgba(180,160,255,${alpha})`;
      ctx.beginPath(); ctx.ellipse(sx, sy, sz, sz*0.55, frac*1.2, 0, Math.PI*2); ctx.fill();
    }
    ctx.restore();
  }

  // Outer wind ring
  const rg = ctx.createRadialGradient(x,y,r*0.8,x,y,windR);
  rg.addColorStop(0, `${color}44`);
  rg.addColorStop(0.5, `${color}22`);
  rg.addColorStop(1, 'transparent');
  ctx.fillStyle = rg;
  ctx.beginPath(); ctx.arc(x, y, windR, 0, Math.PI*2); ctx.fill();

  // Eye wall (bright ring)
  ctx.strokeStyle = color; ctx.lineWidth = 3.5;
  ctx.globalAlpha = 0.7 + Math.sin(t*3)*0.15;
  ctx.beginPath(); ctx.arc(x, y, r, 0, Math.PI*2); ctx.stroke();
  ctx.globalAlpha = 1;

  // Eye centre (calm)
  const eg = ctx.createRadialGradient(x,y,0,x,y,r*0.75);
  eg.addColorStop(0,'rgba(255,255,255,0.22)'); eg.addColorStop(1,'transparent');
  ctx.fillStyle = eg;
  ctx.beginPath(); ctx.arc(x, y, r*0.75, 0, Math.PI*2); ctx.fill();

  // Label
  ctx.fillStyle='rgba(255,255,255,.85)'; ctx.strokeStyle='rgba(0,0,0,.3)'; ctx.lineWidth=2.5;
  ctx.font='bold 10px Nunito,sans-serif'; ctx.textAlign='center';
  ctx.strokeText('🌀 EYE',x,y-r-6); ctx.fillText('🌀 EYE',x,y-r-6);
  ctx.font='bold 9px Nunito,sans-serif';
  ctx.fillStyle = color;
  ctx.fillText(`${wind} km/h`,x,y+r+14);

  ctx.restore();
}

// ── TYPHOON TRACK TRAIL ── called inside renderSim
function drawTyphoonTrack(ctx) {
  if (!typhTrackOverlay.length || !selectedTyphoon) return;
  const td = TYPHOON_DATA[selectedTyphoon];
  ctx.save();
  // Draw the full track path
  ctx.setLineDash([5, 5]);
  ctx.strokeStyle = td.color + '55';
  ctx.lineWidth = 1.5;
  ctx.beginPath();
  typhTrackOverlay.forEach((p,i) => i===0 ? ctx.moveTo(p.x,p.y) : ctx.lineTo(p.x,p.y));
  ctx.stroke();
  ctx.setLineDash([]);
  // Draw track dots up to current step
  typhTrackOverlay.slice(0, replayStep).forEach((p, i) => {
    const frac = (i+1)/typhTrackOverlay.length;
    ctx.globalAlpha = 0.3 + frac*0.5;
    ctx.fillStyle = td.color;
    ctx.beginPath(); ctx.arc(p.x, p.y, 3+frac*3, 0, Math.PI*2); ctx.fill();
  });
  ctx.globalAlpha = 1;
  ctx.restore();
}

// ── WEATHER MAP OVERLAY (station dots on terrain) ──
// Draw small colored circles showing real weather intensity per point
function drawWeatherOverlay(ctx, t) {
  if (!liveWeather) return;
  // Overlay a subtle heat map of rainfall/wind intensity
  const intensity = (liveWeather.rain / 20 + liveWeather.wind / 100) * 0.5;
  if (intensity < 0.05) return;

  ctx.save();
  ctx.globalAlpha = intensity * 0.35;
  // Soft rain overlay wash
  const rwg = ctx.createLinearGradient(0, 0, 0, simH);
  rwg.addColorStop(0, 'transparent');
  rwg.addColorStop(0.4, `rgba(109,200,232,${intensity*0.3})`);
  rwg.addColorStop(1, `rgba(58,155,191,${intensity*0.25})`);
  ctx.fillStyle = rwg;
  ctx.fillRect(0, 0, simW, simH);
  ctx.globalAlpha = 1;

  // Live data label in map corner
  ctx.fillStyle = 'rgba(255,255,255,.8)';
  ctx.strokeStyle = 'rgba(30,80,120,.5)'; ctx.lineWidth = 2;
  ctx.font = 'bold 9px Nunito,sans-serif'; ctx.textAlign = 'left';
  const lbl = `🌐 LIVE: ${liveWeather.temp.toFixed(0)}°C  💧${liveWeather.rain.toFixed(1)}mm/h  💨${liveWeather.wind.toFixed(0)}km/h`;
  ctx.strokeText(lbl, 12, simH - 28); ctx.fillText(lbl, 12, simH - 28);
  ctx.restore();
}

// ── INIT WEATHER FETCH ──
// Fetch immediately and then every 10 minutes
function initWeather() {
  fetchLiveWeather(currentDEMKey);
  if (wxFetchInterval) clearInterval(wxFetchInterval);
  wxFetchInterval = setInterval(() => fetchLiveWeather(currentDEMKey), 10 * 60 * 1000);
}



