// ══════════════════════════════════════════════════════════════
//  WEEK 4 — 3D TERRAIN VIEW (Three.js WebGL) — FIXED
// ══════════════════════════════════════════════════════════════

let three = null;

function init3DView() {
  if (three) return;

  const canvas3d = document.getElementById('canvas-3d');
  const container = document.getElementById('center');
  const W = container.clientWidth || 800;
  const H = container.clientHeight || 600;

  // ── Renderer ──
  const renderer = new THREE.WebGLRenderer({ canvas: canvas3d, antialias: true });
  renderer.setSize(W, H);
  renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));
  renderer.shadowMap.enabled = true;
  renderer.setClearColor(0xd4eeff, 1);

  // ── Scene + fog ──
  const scene = new THREE.Scene();
  scene.background = new THREE.Color(0xd4eeff);
  scene.fog = new THREE.Fog(0xd4eeff, 60, 120);

  // ── Camera ──
  const camera = new THREE.PerspectiveCamera(50, W / H, 0.1, 300);
  camera.position.set(0, 22, 30);
  camera.lookAt(0, 2, 0);

  // ── Lights ──
  scene.add(new THREE.AmbientLight(0xffffff, 0.7));
  const sun = new THREE.DirectionalLight(0xfff8e0, 1.2);
  sun.position.set(20, 40, 30);
  sun.castShadow = true;
  sun.shadow.mapSize.set(2048, 2048);
  sun.shadow.camera.left = -35; sun.shadow.camera.right = 35;
  sun.shadow.camera.top = 35;   sun.shadow.camera.bottom = -35;
  sun.shadow.camera.near = 0.5; sun.shadow.camera.far = 150;
  scene.add(sun);
  const fill = new THREE.DirectionalLight(0xb0d8ff, 0.5);
  fill.position.set(-15, 10, -10);
  scene.add(fill);

  // ── Sky dome ──
  const skyGeo = new THREE.SphereGeometry(110, 16, 8);
  const skyMat = new THREE.ShaderMaterial({
    side: THREE.BackSide,
    vertexShader: `
      varying float vY;
      void main() { vY = normalize(position).y; gl_Position = projectionMatrix * modelViewMatrix * vec4(position,1.0); }`,
    fragmentShader: `
      varying float vY;
      void main() {
        vec3 top = vec3(0.48,0.72,0.98);
        vec3 bot = vec3(0.82,0.92,1.0);
        gl_FragColor = vec4(mix(bot,top,max(0.0,vY)),1.0);
      }`
  });
  scene.add(new THREE.Mesh(skyGeo, skyMat));

  // ── BUILD TERRAIN using BufferGeometry (correct approach) ──
  // We build a grid of quads manually — no PlaneGeometry rotation issues
  const G = 71; // 72x72 grid = 71 segments each way
  const SIZE = 28.0;
  const HALF = SIZE / 2;
  const H_SCALE = 10.0;  // max height in world units

  // Preallocate arrays
  const vtxCount = (G+1) * (G+1);
  const positions = new Float32Array(vtxCount * 3);
  const normals   = new Float32Array(vtxCount * 3);
  const colorsArr = new Float32Array(vtxCount * 3);
  // Index buffer: 2 triangles per quad
  const indices = new Uint32Array(G * G * 6);

  // Build index buffer once (never changes)
  let idx = 0;
  for (let row = 0; row < G; row++) {
    for (let col = 0; col < G; col++) {
      const a = row * (G+1) + col;
      const b = a + 1;
      const c = (row+1) * (G+1) + col;
      const d = c + 1;
      indices[idx++] = a; indices[idx++] = c; indices[idx++] = b;
      indices[idx++] = b; indices[idx++] = c; indices[idx++] = d;
    }
  }

  const terrainGeo = new THREE.BufferGeometry();
  terrainGeo.setIndex(new THREE.BufferAttribute(indices, 1));
  terrainGeo.setAttribute('position', new THREE.BufferAttribute(positions, 3));
  terrainGeo.setAttribute('normal',   new THREE.BufferAttribute(normals, 3));
  terrainGeo.setAttribute('color',    new THREE.BufferAttribute(colorsArr, 3));

  function elevColor(h, wn) {
    if (h < wn - 0.008) {
      const d = Math.min(1, (wn - h) * 7);
      return [0.15+d*0.05, 0.48+d*0.1, 0.78+d*0.12];
    }
    if (h < wn + 0.012) return [0.65, 0.90, 0.97];
    if (h < 0.04)  return [0.88, 0.95, 0.78];
    if (h < 0.10)  return [0.68, 0.84, 0.48];
    if (h < 0.22)  return [0.50, 0.72, 0.30];
    if (h < 0.38)  return [0.38, 0.60, 0.22];
    if (h < 0.55)  return [0.36, 0.50, 0.20];
    if (h < 0.70)  return [0.58, 0.50, 0.32];
    if (h < 0.85)  return [0.75, 0.70, 0.55];
    return [0.92, 0.92, 0.94];
  }

  function updateTerrainGeometry(wl) {
    const wn = wl / 100;
    for (let row = 0; row <= G; row++) {
      for (let col = 0; col <= G; col++) {
        const vi = row * (G+1) + col;
        // Sample from heights[] — heights is (G+1)x(G+1)
        const h = heights[row * (G+1) + col] || 0;
        const x = (col / G) * SIZE - HALF;
        const y = h * H_SCALE;
        const z = (row / G) * SIZE - HALF;
        positions[vi*3]   = x;
        positions[vi*3+1] = y;
        positions[vi*3+2] = z;
        const [cr, cg, cb] = elevColor(h, wn);
        colorsArr[vi*3]   = cr;
        colorsArr[vi*3+1] = cg;
        colorsArr[vi*3+2] = cb;
      }
    }
    terrainGeo.attributes.position.needsUpdate = true;
    terrainGeo.attributes.color.needsUpdate = true;
    terrainGeo.computeVertexNormals();
  }

  const terrainMat = new THREE.MeshLambertMaterial({ vertexColors: true });
  const terrainMesh = new THREE.Mesh(terrainGeo, terrainMat);
  terrainMesh.receiveShadow = true;
  terrainMesh.castShadow = false;
  scene.add(terrainMesh);

  // ── Road network overlay (canvas texture drawn from real map data) ──
  const roadCanvas = document.createElement('canvas');
  roadCanvas.width = roadCanvas.height = 512;
  const roadCtx = roadCanvas.getContext('2d');

  function drawRoadTexture(cityKey) {
    roadCtx.clearRect(0, 0, 512, 512);
    roadCtx.fillStyle = 'rgba(0,0,0,0)';
    roadCtx.fillRect(0, 0, 512, 512);

    const roads = CITY_ROADS[cityKey] || CITY_ROADS.tainan;

    // Draw major roads
    roads.major.forEach(path => {
      roadCtx.beginPath();
      roadCtx.strokeStyle = 'rgba(255,180,40,0.7)';
      roadCtx.lineWidth = 3.5;
      roadCtx.lineCap = 'round'; roadCtx.lineJoin = 'round';
      path.forEach(([px,py], i) => i===0 ? roadCtx.moveTo(px*512,py*512) : roadCtx.lineTo(px*512,py*512));
      roadCtx.stroke();
    });
    // Draw minor roads
    roads.minor.forEach(path => {
      roadCtx.beginPath();
      roadCtx.strokeStyle = 'rgba(255,255,255,0.45)';
      roadCtx.lineWidth = 1.5;
      path.forEach(([px,py], i) => i===0 ? roadCtx.moveTo(px*512,py*512) : roadCtx.lineTo(px*512,py*512));
      roadCtx.stroke();
    });
    // Draw rivers
    if (roads.rivers) roads.rivers.forEach(path => {
      roadCtx.beginPath();
      roadCtx.strokeStyle = 'rgba(80,160,220,0.6)';
      roadCtx.lineWidth = 4;
      path.forEach(([px,py], i) => i===0 ? roadCtx.moveTo(px*512,py*512) : roadCtx.lineTo(px*512,py*512));
      roadCtx.stroke();
    });
    // Labels for key locations
    roadCtx.font = 'bold 11px sans-serif';
    roadCtx.fillStyle = 'rgba(60,40,80,0.85)';
    roadCtx.textAlign = 'center';
    if (roads.labels) roads.labels.forEach(([px,py,txt]) => {
      roadCtx.strokeStyle = 'rgba(255,255,255,0.6)'; roadCtx.lineWidth = 3;
      roadCtx.strokeText(txt, px*512, py*512);
      roadCtx.fillText(txt, px*512, py*512);
    });
    roadTex.needsUpdate = true;
  }

  const roadTex = new THREE.CanvasTexture(roadCanvas);
  const roadPlaneGeo = new THREE.PlaneGeometry(SIZE*0.99, SIZE*0.99);
  roadPlaneGeo.rotateX(-Math.PI/2);
  const roadPlaneMat = new THREE.MeshBasicMaterial({
    map: roadTex, transparent: true, depthWrite: false,
    polygonOffset: true, polygonOffsetFactor: -2, polygonOffsetUnits: -2,
  });
  const roadMesh = new THREE.Mesh(roadPlaneGeo, roadPlaneMat);
  roadMesh.position.y = 0.08;
  scene.add(roadMesh);

  // ── Water plane ──
  const waterGeo = new THREE.PlaneGeometry(SIZE, SIZE);
  waterGeo.rotateX(-Math.PI / 2);
  const waterMat = new THREE.MeshLambertMaterial({
    color: 0x4ab0e0, transparent: true, opacity: 0.52,
    side: THREE.DoubleSide
  });
  const waterMesh = new THREE.Mesh(waterGeo, waterMat);
  waterMesh.renderOrder = 1;
  waterMesh.visible = false;
  scene.add(waterMesh);

  // ── Mouse / touch orbit ──
  let isDragging=false, isRMB=false, lastX=0, lastY=0;
  let theta=0.3, phi=1.0, radius=38, panX=0, panZ=0;

  function updateCam() {
    const sp=Math.sin(phi), cp=Math.cos(phi), st=Math.sin(theta), ct=Math.cos(theta);
    camera.position.set(panX+radius*sp*st, radius*cp+2, panZ+radius*sp*ct);
    camera.lookAt(panX, 2, panZ);
  }
  updateCam();

  canvas3d.addEventListener('mousedown', e=>{
    isDragging=true; isRMB=e.button===2; lastX=e.clientX; lastY=e.clientY;
    e.preventDefault();
  });
  canvas3d.addEventListener('contextmenu', e=>e.preventDefault());
  window.addEventListener('mousemove', e=>{
    if(!isDragging) return;
    const dx=e.clientX-lastX, dy=e.clientY-lastY;
    if(isRMB){ panX-=dx*0.025; panZ-=dy*0.025; }
    else { theta-=dx*0.006; phi=Math.max(0.12,Math.min(1.48,phi+dy*0.006)); }
    lastX=e.clientX; lastY=e.clientY; updateCam();
  });
  window.addEventListener('mouseup', ()=>isDragging=false);
  canvas3d.addEventListener('wheel', e=>{
    radius=Math.max(6,Math.min(90,radius+e.deltaY*0.035));
    updateCam(); e.preventDefault();
  },{passive:false});

  let ptDist=0,ptX=0,ptY=0;
  canvas3d.addEventListener('touchstart',e=>{
    if(e.touches.length===1){ptX=e.touches[0].clientX;ptY=e.touches[0].clientY;}
    if(e.touches.length===2) ptDist=Math.hypot(e.touches[0].clientX-e.touches[1].clientX,e.touches[0].clientY-e.touches[1].clientY);
  });
  canvas3d.addEventListener('touchmove',e=>{
    e.preventDefault();
    if(e.touches.length===1){
      const dx=e.touches[0].clientX-ptX,dy=e.touches[0].clientY-ptY;
      theta-=dx*0.007; phi=Math.max(0.12,Math.min(1.48,phi+dy*0.007));
      ptX=e.touches[0].clientX;ptY=e.touches[0].clientY; updateCam();
    }
    if(e.touches.length===2){
      const d=Math.hypot(e.touches[0].clientX-e.touches[1].clientX,e.touches[0].clientY-e.touches[1].clientY);
      radius=Math.max(6,Math.min(90,radius-(d-ptDist)*0.05));
      ptDist=d; updateCam();
    }
  },{passive:false});

  // ── Resize ──
  function resize3D(){
    if(!three) return;
    const W2=container.clientWidth, H2=container.clientHeight;
    if(!W2||!H2) return;
    renderer.setSize(W2,H2);
    camera.aspect=W2/H2; camera.updateProjectionMatrix();
  }
  window.addEventListener('resize', resize3D);

  // ── Render loop ──
  let frame3=0;
  function render3D(){
    if(!three||!three.active) return;
    frame3++;
    const wl=parseFloat(document.getElementById('s-wl').value)||0;
    const wn=wl/100;

    // Animate water
    waterMesh.visible = wl > 0.5;
    waterMesh.position.y = wn*H_SCALE + Math.sin(frame3*0.035)*0.12;
    waterMat.opacity = 0.38+wn*0.28;
    waterMat.color.setHSL(0.55-wn*0.04, 0.7+wn*0.15, 0.52-wn*0.06);

    // Rebuild terrain colours every 3 frames
    if(frame3%3===0) updateTerrainGeometry(wl);

    // Slow auto-rotate
    if(!isDragging) theta+=0.0006;
    updateCam();

    renderer.render(scene, camera);
    requestAnimationFrame(render3D);
  }

  // Initial build
  updateTerrainGeometry(0);
  // Draw roads for default city
  drawRoadTexture(currentDEMKey||'tainan');

  three = {
    renderer, scene, camera, terrainMesh, waterMesh, waterMat,
    updateTerrainGeometry, render3D, active: false,
    updateCamera: updateCam, resize3D, drawRoadTexture
  };
}

let currentViewMode = '2d';
function setView(mode) {
  currentViewMode = mode;
  const center = document.getElementById('center');
  center.className = `card view-${mode}`;
  center.style.overflow = 'hidden';

  document.querySelectorAll('.vtab').forEach(t => t.classList.remove('active'));
  const tabEl = document.getElementById(`vtab-${mode}`);
  if(tabEl) tabEl.classList.add('active');

  if (mode === '3d') {
    init3DView();
    three.active = true;
    three.resize3D();
    three.render3D();
  } else {
    if (three) three.active = false;
  }
  // Update HUD label
  const labels = {'2d':'ISO TERRAIN','map':'CITY MAP','3d':'3D TERRAIN'};
  const htl = document.getElementById('hud-tl-txt');
  if(htl) htl.textContent = `FLOODSIGHT v8 · ${labels[mode]||''}`;
}

let nightMode = false;
function toggleNightMode(){
  nightMode = !nightMode;
  document.body.classList.toggle('night-mode', nightMode);
  const btn = document.getElementById('night-btn');
  if(btn) btn.textContent = nightMode ? '☀️ Day' : '🌙 Night';
  // Rebuild starfield
  if(nightMode) try{buildStarfield();}catch(e){}
  // Add/remove tiny micro-stars inside the header
  const hdr = document.getElementById('header');
  if(nightMode){
    // Add 30 tiny stars scattered in header
    for(let i=0;i<30;i++){
      const s=document.createElement('div'); s.className='hdr-star';
      const sz=0.8+Math.random()*1.4;
      const dur=1+Math.random()*2.5;
      const delay=-Math.random()*3;
      s.style.cssText=`width:${sz}px;height:${sz}px;left:${Math.random()*100}%;top:${10+Math.random()*80}%;animation-duration:${dur}s;animation-delay:${delay}s;z-index:0;position:absolute;pointer-events:none;`;
      hdr.appendChild(s);
    }
  } else {
    hdr.querySelectorAll('.hdr-star').forEach(s=>s.remove());
  }
}

