// Minimal QR code generator (pure JS, no library needed)
// Uses a simple URL-encoding approach with a visual canvas render
function openARModal() {
  document.getElementById('ar-modal').classList.add('show');
  drawQRCode();
}
function closeARModal() {
  document.getElementById('ar-modal').classList.remove('show');
}

function drawQRCode() {
  const div = document.getElementById('ar-qr-div');
  div.innerHTML = ''; // clear previous

  // Use the real FloodSight AR GitHub Pages URL
  // When hosted locally, points to the AR page
  const baseURL = window.location.href.replace('floodsight-week4.html','').replace('floodsight-week4b.html','');
  const arURL = baseURL + 'floodsight-ar.html';

  try {
    new QRCode(div, {
      text: arURL,
      width: 180,
      height: 180,
      colorDark: '#2a2a4a',
      colorLight: '#ffffff',
      correctLevel: QRCode.CorrectLevel.M,
    });
  } catch(e) {
    // Fallback if QRCode lib fails — show URL as text
    div.innerHTML = '<div style="width:180px;height:180px;display:flex;align-items:center;justify-content:center;text-align:center;font-size:.6rem;color:#4a3550;padding:10px;word-break:break-all;">' +
      '📱 Open this file directly on your phone:<br><br><strong>' + arURL + '</strong></div>';
  }
}

// Close AR modal on backdrop click
document.getElementById('ar-modal').addEventListener('click', function(e) {
  if (e.target === this) closeARModal();
});

