// Historical reference damage data (billion NT$)
const HISTORICAL_DAMAGE = {
  morakot2009: 109.8,
  nari2001:    35.2,
  herb1996:    74.1,
  krathon2024: 12.4,
};

let popOverlayOn = false;
let evacOverlayOn = false;

// ── Compute damage and population at risk ──
function computeWeek5(wl, cityKey) {
  const wlM = wl / 10;   // 0-10 metres
  const wn  = wl / 100;  // normalised 0-1
  const cityPop = CITY_POPULATION[cityKey];
  if (!cityPop) return null;

  // ── Part A: Population at Risk ──
  let totalAtRisk = 0;
  const districtResults = cityPop.districts.map(d => {
    // District floods if water level exceeds district elevation
    const floodDepth = Math.max(0, wn - d.elev);
    const floodedFrac = Math.min(1, floodDepth * 8);  // gradual inundation
    const atRisk = Math.round(d.pop * floodedFrac);
    totalAtRisk += atRisk;
    return { ...d, atRisk, floodedFrac, floodDepth };
  });

  const pctAffected = (totalAtRisk / cityPop.total * 100).toFixed(1);

  // ── Part B: Economic Damage ──
  const floodedPop = totalAtRisk / 1000;  // thousands

  // Residential: households * cost * depth factor
  const depthFactor = Math.min(3.5, 1 + wlM * 0.4);
  const householdsFlooded = floodedPop * DAMAGE_PARAMS.residential.householdsPerThousandPop;
  const dmgResidential = householdsFlooded * DAMAGE_PARAMS.residential.costPerHousehold * depthFactor;

  // Agriculture: rice paddies + aquaculture
  const haPerK = DAMAGE_PARAMS.agriculture.haPerThousandPop[cityKey] || 5;
  const haFlooded = floodedPop * haPerK * Math.min(1, wn * 2);
  const dmgAgriculture = haFlooded *
    (cityPop.farmPct * DAMAGE_PARAMS.agriculture.riceCostPerHa +
     (1-cityPop.farmPct) * DAMAGE_PARAMS.agriculture.aquaculturePerHa * 0.1);

  // Infrastructure: roads + bridges
  const city = REAL_DEM[cityKey];
  const areaSqKm = city ? ((city.lat_range[1]-city.lat_range[0]) * 111) *
                          ((city.lon_range[1]-city.lon_range[0]) * 101) * wn * 1.2 : 50;
  const roadsFlooded = areaSqKm * DAMAGE_PARAMS.infrastructure.roadsPerSqKm;
  const bridgesFlooded = Math.floor(roadsFlooded / 12);
  const dmgInfra = roadsFlooded * DAMAGE_PARAMS.infrastructure.roadCostPerKm +
                   bridgesFlooded * DAMAGE_PARAMS.infrastructure.bridgeCostEach;

  // Business disruption
  const employeesAffected = floodedPop * DAMAGE_PARAMS.business.employeesPerThousandPop;
  const dmgBusiness = employeesAffected * DAMAGE_PARAMS.business.costPerEmployee *
                      DAMAGE_PARAMS.business.daysOfDisruption * cityPop.businessPct;

  const dmgTotal = dmgResidential + dmgAgriculture + dmgInfra + dmgBusiness;

  // Historical comparison
  let compareText = '';
  const dmgBillion = dmgTotal / 1e9;
  if (dmgBillion > 80)       compareText = `⚠️ Exceeds Morakot 2009 (NT$${HISTORICAL_DAMAGE.morakot2009}B)`;
  else if (dmgBillion > 25)  compareText = `≈ Similar to Nari 2001 (NT$${HISTORICAL_DAMAGE.nari2001}B)`;
  else if (dmgBillion > 8)   compareText = `≈ Similar to Krathon 2024 (NT$${HISTORICAL_DAMAGE.krathon2024}B)`;
  else if (dmgBillion > 0.5) compareText = `Minor event — local damage only`;
  else                       compareText = '— No significant economic impact —';

  return {
    districtResults, totalAtRisk, pctAffected,
    dmgResidential, dmgAgriculture, dmgInfra, dmgBusiness, dmgTotal,
    compareText, dmgBillion,
  };
}

function fmtNT(val) {
  if (val >= 1e9) return `NT$${(val/1e9).toFixed(2)}B`;
  if (val >= 1e6) return `NT$${(val/1e6).toFixed(1)}M`;
  if (val >= 1e3) return `NT$${(val/1e3).toFixed(0)}K`;
  return `NT$${Math.round(val)}`;
}

// ── Update Week 5 UI ──
function updateWeek5UI(wl, cityKey) {
  const result = computeWeek5(wl, cityKey);
  if (!result) return;

  // ── Part A: District Table ──
  const tbody = document.getElementById('pop-tbody');
  tbody.innerHTML = '';
  result.districtResults
    .sort((a,b) => b.atRisk - a.atRisk)
    .slice(0, 6)  // show top 6 most affected
    .forEach(d => {
      const flooded = d.floodedFrac > 0.6;
      const warn    = d.floodedFrac > 0.15;
      const tr = document.createElement('tr');
      tr.className = flooded ? 'flooded-row' : warn ? 'warn-row' : '';
      const statusDot = flooded ? '🔴' : warn ? '🟡' : '🟢';
      const badgeColor = flooded ? 'rgba(255,112,150,.2);color:#c03060' :
                         warn    ? 'rgba(255,200,100,.2);color:#b06010' :
                                   'rgba(125,232,176,.2);color:#1a8050';
      tr.innerHTML = `
        <td>${statusDot} ${d.name.split(' ')[0]}</td>
        <td>${(d.pop/1000).toFixed(0)}k</td>
        <td><span style="background:${badgeColor};padding:1px 7px;border-radius:100px;font-size:.6rem;font-weight:800;">${d.atRisk > 0 ? d.atRisk.toLocaleString() : '—'}</span></td>
        <td style="font-size:.6rem;">${d.floodedFrac > 0.6 ? 'FLOODED' : d.floodedFrac > 0.15 ? 'WARN' : 'SAFE'}</td>
      `;
      tbody.appendChild(tr);
    });

  document.getElementById('pop-total-at-risk').textContent = result.totalAtRisk.toLocaleString();
  document.getElementById('pop-pct-affected').textContent =
    `${result.pctAffected}% of ${(CITY_POPULATION[cityKey].total/1000).toFixed(0)}k city population`;

  // ── Part B: Damage Breakdown ──
  document.getElementById('dmg-residential').textContent = fmtNT(result.dmgResidential);
  document.getElementById('dmg-agriculture').textContent = fmtNT(result.dmgAgriculture);
  document.getElementById('dmg-infra').textContent       = fmtNT(result.dmgInfra);
  document.getElementById('dmg-business').textContent    = fmtNT(result.dmgBusiness);
  document.getElementById('dmg-total-val').textContent   = fmtNT(result.dmgTotal);
  document.getElementById('dmg-compare-txt').textContent = result.compareText;

  // Also update bottom bar
  document.getElementById('bs-dmg').textContent = fmtNT(result.dmgTotal);
  // Update people at risk with real number
  document.getElementById('bs-pop').textContent = result.totalAtRisk.toLocaleString();

  // ── Part C: Evacuation Routes ──
  updateEvacRoutes(wl, cityKey, result);

  // ── Population heatmap on canvas ──
  if (popOverlayOn) drawPopulationHeatmap(result.districtResults, cityKey);
  if (evacOverlayOn) drawEvacOverlay(wl, cityKey, result);
}

