function updateEvacRoutes(wl, cityKey, popResult) {
  const wn = wl / 100;
  const routeData = EVAC_ROUTES[cityKey];
  if (!routeData) return;

  const routeList = document.getElementById('route-list');
  const shelterList = document.getElementById('shelter-list');

  // ── Status bar ──
  const evacDot = document.getElementById('evac-dot');
  const evacText = document.getElementById('evac-status-text');
  const evacSub  = document.getElementById('evac-status-sub');

  const blockedRoutes = routeData.routes.filter(r => wn > r.elevThresh + 0.04).length;
  const cautionRoutes = routeData.routes.filter(r => wn > r.elevThresh && wn <= r.elevThresh + 0.04).length;

  if (wl < 15) {
    evacDot.style.cssText  = 'background:var(--safe);box-shadow:0 0 6px var(--safe);';
    evacText.textContent   = '✅ All routes clear';
    evacSub.textContent    = 'No evacuation required';
  } else if (blockedRoutes === 0 && cautionRoutes > 0) {
    evacDot.style.cssText  = 'background:var(--warn);box-shadow:0 0 6px var(--warn);';
    evacText.textContent   = `⚠️ ${cautionRoutes} route(s) at risk`;
    evacSub.textContent    = 'Monitor conditions — prepare to evacuate';
  } else if (blockedRoutes > 0) {
    evacDot.style.cssText  = 'background:var(--danger);box-shadow:0 0 6px var(--danger);animation:wxPulse 1s infinite;';
    evacText.textContent   = `🚨 ${blockedRoutes} route(s) BLOCKED!`;
    evacSub.textContent    = `Evacuate immediately via open routes! ${popResult.totalAtRisk.toLocaleString()} at risk`;
  }

  // ── Route items ──
  routeList.innerHTML = '';
  routeData.routes.forEach(r => {
    const blocked = wn > r.elevThresh + 0.04;
    const caution = wn > r.elevThresh && !blocked;
    const cls = blocked ? 'blocked' : caution ? 'warn' : 'open';
    const badge = blocked ? 'blocked' : caution ? 'caution' : 'open';
    const badgeTxt = blocked ? '🚫 BLOCKED' : caution ? '⚠️ CAUTION' : '✅ OPEN';
    const div = document.createElement('div');
    div.className = `route-item ${cls}`;
    div.innerHTML = `
      <div class="route-top">
        <div class="route-name">${r.name}</div>
        <span class="route-badge ${badge}">${badgeTxt}</span>
      </div>
      <div class="route-sub">→ ${r.dest}</div>
    `;
    routeList.appendChild(div);
  });

  // ── Shelters ──
  shelterList.innerHTML = '';
  routeData.shelters.forEach(s => {
    const div = document.createElement('div');
    div.className = 'shelter-item';
    div.innerHTML = `
      <div class="shelter-icon">${s.icon}</div>
      <div>
        <div class="shelter-name">${s.name}</div>
        <div class="shelter-cap">Capacity: ${s.cap.toLocaleString()}</div>
      </div>
      <div class="shelter-dist">${s.dist}</div>
    `;
    shelterList.appendChild(div);
  });
}

// ══════════════════════════════════════════════════════════════
//  MAP OVERLAYS — Population heatmap + Evacuation on canvas
// ══════════════════════════════════════════════════════════════

let overlayState = { pop: false, evac: false };

function toggleOverlay(type) {
  overlayState[type] = !overlayState[type];
  const btn = document.getElementById('tog-' + type);
  btn.classList.toggle('on', overlayState[type]);

  const popCanvas = document.getElementById('pop-canvas');
  if (!overlayState.pop && !overlayState.evac) {
    popCanvas.style.display = 'none';
    const ctx = popCanvas.getContext('2d');
    ctx.clearRect(0, 0, popCanvas.width, popCanvas.height);
  } else {
    popCanvas.style.display = 'block';
    const wl = parseFloat(document.getElementById('s-wl').value) || 0;
    const result = computeWeek5(wl, currentDEMKey);
    if (result) {
      if (overlayState.pop) drawPopulationHeatmap(result.districtResults, currentDEMKey);
      if (overlayState.evac) drawEvacOverlay(wl, currentDEMKey, result);
    }
  }
}

function drawPopulationHeatmap(districts, cityKey) {
  const canvas = document.getElementById('pop-canvas');
  canvas.width  = simW;
  canvas.height = simH;
  const ctx = canvas.getContext('2d');
  ctx.clearRect(0, 0, simW, simH);

  const city = REAL_DEM[cityKey];
  if (!city) return;
  const [latMin, latMax] = city.lat_range;
  const [lonMin, lonMax] = city.lon_range;

  districts.forEach(d => {
    // Map district lat/lon position (normalised 0-1) to canvas
    const cx = d.lon * simW;
    const cy = (1 - d.lat) * simH;
    const density = d.pop / 400000;  // normalise to max ~400k
    const radius  = Math.max(22, 18 + density * 60) * (simW / 900);
    const flood   = d.floodedFrac;

    // Colour: green (safe) → yellow → red (flooded)
    const r = Math.round(80 + flood * 175);
    const g = Math.round(200 - flood * 160);
    const b = Math.round(80 - flood * 60);
    const alpha = 0.35 + density * 0.25;

    const grd = ctx.createRadialGradient(cx, cy, 0, cx, cy, radius);
    grd.addColorStop(0,   `rgba(${r},${g},${b},${alpha + 0.2})`);
    grd.addColorStop(0.5, `rgba(${r},${g},${b},${alpha})`);
    grd.addColorStop(1,   `rgba(${r},${g},${b},0)`);
    ctx.fillStyle = grd;
    ctx.beginPath(); ctx.arc(cx, cy, radius, 0, Math.PI*2); ctx.fill();

    // Label for large districts
    if (d.pop > 100000) {
      ctx.font = `bold ${Math.max(9, 8 + density*4)}px Nunito,sans-serif`;
      ctx.fillStyle = 'rgba(255,255,255,.9)';
      ctx.strokeStyle = 'rgba(0,0,0,.4)'; ctx.lineWidth = 2.5;
      ctx.textAlign = 'center';
      const shortName = d.name.split(' ')[0];
      ctx.strokeText(shortName, cx, cy+3);
      ctx.fillText(shortName, cx, cy+3);
      ctx.font = `${Math.max(7,6+density*3)}px Nunito,sans-serif`;
      ctx.fillStyle = flood > 0.3 ? '#ffcccc' : '#ffffaa';
      ctx.strokeText((d.pop/1000).toFixed(0)+'k', cx, cy+13);
      ctx.fillText((d.pop/1000).toFixed(0)+'k', cx, cy+13);
    }
  });

  // ── 🌡️ HEATMAP BREATHING — subtle cyan breath overlay ──
  const breathAlpha = 0.028 + 0.018 * Math.sin(waveTime * 1.8);
  ctx.save();
  ctx.globalAlpha = breathAlpha;
  const bg = ctx.createLinearGradient(0, 0, simW, simH);
  bg.addColorStop(0, 'rgba(109,200,232,1)');
  bg.addColorStop(1, 'rgba(122,144,255,1)');
  ctx.fillStyle = bg;
  ctx.fillRect(0, 0, simW, simH);
  ctx.restore();

  // Legend
  ctx.save();
  const lx = 10, ly = simH - 58;
  ctx.fillStyle = 'rgba(255,255,255,.72)';
  ctx.strokeStyle = 'rgba(180,160,220,.4)'; ctx.lineWidth = 1;
  ctx.beginPath(); ctx.roundRect(lx, ly, 150, 50, 8); ctx.fill(); ctx.stroke();
  ctx.font = 'bold 8px Nunito,sans-serif'; ctx.textAlign = 'left';
  ctx.fillStyle = '#4a3550'; ctx.fillText('👥 Population Density', lx+8, ly+14);
  const lgrd = ctx.createLinearGradient(lx+8, 0, lx+142, 0);
  lgrd.addColorStop(0, 'rgba(80,200,80,.7)');
  lgrd.addColorStop(0.5, 'rgba(255,200,50,.8)');
  lgrd.addColorStop(1, 'rgba(255,60,60,.9)');
  ctx.fillStyle = lgrd;
  ctx.beginPath(); ctx.roundRect(lx+8, ly+22, 134, 8, 4); ctx.fill();
  ctx.fillStyle = '#4a3550'; ctx.font = '7px Nunito,sans-serif';
  ctx.fillText('Safe', lx+8, ly+42); ctx.textAlign = 'right';
  ctx.fillText('Flooded', lx+142, ly+42);
  ctx.restore();
}

function drawEvacOverlay(wl, cityKey, result) {
  const canvas = document.getElementById('pop-canvas');
  const ctx = canvas.getContext('2d');
  const wn = wl / 100;
  const routeData = EVAC_ROUTES[cityKey];
  const cityRoads = CITY_ROADS[cityKey];
  if (!routeData || !cityRoads) return;

  // Draw evacuation route arrows on the canvas
  cityRoads.major.forEach((path, i) => {
    const route = routeData.routes[i % routeData.routes.length];
    if (!route) return;
    const blocked = wn > route.elevThresh + 0.04;
    const caution = wn > route.elevThresh && !blocked;
    const color = blocked ? 'rgba(255,80,100,.8)' : caution ? 'rgba(255,190,50,.8)' : 'rgba(80,220,140,.8)';

    ctx.save();
    ctx.strokeStyle = color;
    ctx.lineWidth   = blocked ? 3 : 2.5;
    ctx.lineCap = 'round';

    if (blocked) {
      // Static dashes for blocked
      ctx.setLineDash([6,4]);
      ctx.lineDashOffset = 0;
    } else if (caution) {
      // Slow flowing dashes
      ctx.setLineDash([10,5]);
      ctx.lineDashOffset = -(waveTime * 18) % 30;
    } else {
      // Fast flowing dashes — traveling in direction of travel
      ctx.setLineDash([12,4]);
      ctx.lineDashOffset = -(waveTime * 40) % 32;
    }

    ctx.beginPath();
    path.forEach(([px,py], j) => {
      const sx = px * simW, sy = py * simH;
      j === 0 ? ctx.moveTo(sx, sy) : ctx.lineTo(sx, sy);
    });
    ctx.stroke();
    ctx.setLineDash([]);

    // Arrow head at end of route
    if (path.length >= 2) {
      const last = path[path.length-1];
      const prev = path[path.length-2];
      const ex = last[0]*simW, ey = last[1]*simH;
      const ax = prev[0]*simW, ay = prev[1]*simH;
      const ang = Math.atan2(ey-ay, ex-ax);
      const hs = 10;
      ctx.fillStyle = color;
      ctx.beginPath();
      ctx.moveTo(ex, ey);
      ctx.lineTo(ex - hs*Math.cos(ang-0.4), ey - hs*Math.sin(ang-0.4));
      ctx.lineTo(ex - hs*Math.cos(ang+0.4), ey - hs*Math.sin(ang+0.4));
      ctx.closePath(); ctx.fill();

      // Status label
      if (!blocked) {
        ctx.font = 'bold 8px Nunito,sans-serif';
        ctx.fillStyle = 'rgba(255,255,255,.9)';
        ctx.strokeStyle = 'rgba(0,0,0,.5)'; ctx.lineWidth = 2;
        ctx.textAlign = 'center';
        const mid = path[Math.floor(path.length/2)];
        ctx.strokeText('EVAC', mid[0]*simW, mid[1]*simH - 4);
        ctx.fillText('EVAC', mid[0]*simW, mid[1]*simH - 4);
      }
    }
    ctx.restore();
  });

  // Shelter icons on map with pulsing rings
  routeData.shelters.forEach((s, i) => {
    const frac = (i + 0.5) / routeData.shelters.length;
    const sx = (0.25 + frac * 0.5) * simW;
    const sy = (0.3 + (i % 2) * 0.35) * simH;
    // Pulsing ring behind icon
    ctx.save();
    const pulseR = 14 + Math.sin(waveTime * 2.5 + i * 1.3) * 5;
    ctx.globalAlpha = 0.35 + 0.25 * Math.abs(Math.sin(waveTime * 2.5 + i * 1.3));
    ctx.strokeStyle = 'rgba(80,220,140,.9)';
    ctx.lineWidth = 2;
    ctx.beginPath(); ctx.arc(sx, sy, pulseR, 0, Math.PI*2); ctx.stroke();
    ctx.globalAlpha = 0.15 + 0.1 * Math.abs(Math.sin(waveTime * 2.5 + i * 1.3));
    ctx.fillStyle = 'rgba(80,220,140,.4)';
    ctx.beginPath(); ctx.arc(sx, sy, pulseR, 0, Math.PI*2); ctx.fill();
    ctx.restore();
    ctx.save();
    ctx.font = '16px sans-serif'; ctx.textAlign = 'center';
    ctx.strokeStyle = 'rgba(255,255,255,.8)'; ctx.lineWidth = 3;
    ctx.strokeText(s.icon, sx, sy);
    ctx.fillText(s.icon, sx, sy);
    ctx.font = 'bold 7px Nunito,sans-serif';
    ctx.fillStyle = 'rgba(60,40,80,.85)'; ctx.strokeStyle = 'rgba(255,255,255,.7)';
    ctx.strokeText(s.name.split(' ')[0], sx, sy+10);
    ctx.fillText(s.name.split(' ')[0], sx, sy+10);
    ctx.restore();
  });
}

// ── Hook into updateAll ──
const _origUpdateAll = updateAll;
updateAll = function() {
  try { _origUpdateAll(); } catch(e) { console.warn("updateAll chain error:", e); }
  const wl = parseFloat(document.getElementById('s-wl').value) || 0;
  updateWeek5UI(wl, currentDEMKey);
  // Refresh overlays if on
  if (overlayState.pop || overlayState.evac) {
    const result = computeWeek5(wl, currentDEMKey);
    const canvas = document.getElementById('pop-canvas');
    canvas.width = simW; canvas.height = simH;
    const ctx = canvas.getContext('2d');
    ctx.clearRect(0,0,simW,simH);
    if (result && overlayState.pop)  drawPopulationHeatmap(result.districtResults, currentDEMKey);
    if (result && overlayState.evac) drawEvacOverlay(wl, currentDEMKey, result);
  }
};

// ── Init Week 5 on load ──
