function exportJSON() {
  const wl  = parseFloat(document.getElementById('s-wl').value)||0;
  const rr  = parseFloat(document.getElementById('s-rr').value)||0;
  const ws  = parseFloat(document.getElementById('s-ws').value)||0;
  const tmp = parseFloat(document.getElementById('s-tmp').value)||28;
  const sat = parseFloat(document.getElementById('s-sat').value)||40;
  const key = currentDEMKey||'tainan';

  const pop5 = computeWeek5(wl, key);
  const ai   = aiFloodForecast(wl, rr*3, ws*1.4, tmp, sat, key);
  const city = REAL_DEM[key];

  const data = {
    meta: {
      system:'FloodSight v6',
      author:'Ipsa',
      generated: new Date().toISOString(),
      city: curLoc, cityKey: key,
      coordinates: city ? { lat: city.lat_range, lon: city.lon_range } : null,
    },
    simulation: {
      waterLevel_m: (wl/10).toFixed(2)*1,
      rainfall_mmh: (rr*3).toFixed(1)*1,
      wind_kmh: (ws*1.4).toFixed(0)*1,
      temperature_C: tmp,
      soilSaturation_pct: sat,
    },
    population: pop5 ? {
      totalAtRisk: pop5.totalAtRisk,
      pctAffected: pop5.pctAffected,
      districts: pop5.districtResults.map(d=>({
        name:d.name, population:d.pop, atRisk:d.atRisk,
        floodedFraction:(d.floodedFrac).toFixed(3)*1
      }))
    } : null,
    damage: pop5 ? {
      residential_NT: Math.round(pop5.dmgResidential),
      agriculture_NT: Math.round(pop5.dmgAgriculture),
      infrastructure_NT: Math.round(pop5.dmgInfra),
      business_NT: Math.round(pop5.dmgBusiness),
      total_NT: Math.round(pop5.dmgTotal),
      historicalComparison: pop5.compareText,
    } : null,
    aiForecast: {
      model:'Physics-informed LSTM surrogate',
      rmse_m: ai.rmse*1,
      forecast_1h_m:  (ai.fc1h*10).toFixed(2)*1,
      forecast_6h_m:  (ai.fc6h*10).toFixed(2)*1,
      forecast_24h_m: (ai.fc24h*10).toFixed(2)*1,
      confidence_1h_pct:  ai.conf1h,
      confidence_6h_pct:  ai.conf6h,
      confidence_24h_pct: ai.conf24h,
    },
    dem: {
      source:'NASA SRTM 30m',
      resolution:'30m',
      gridSize:'36x36 per city',
      elevMin_m: city ? Math.round(REAL_DEM[key].grid.reduce((a,b)=>a<b?a:b)) : null,
      elevMax_m: city ? Math.round(REAL_DEM[key].grid.reduce((a,b)=>a>b?a:b)) : null,
    }
  };

  const blob = new Blob([JSON.stringify(data,null,2)], {type:'application/json'});
  const url  = URL.createObjectURL(blob);
  const a    = document.createElement('a');
  a.href = url;
  a.download = `floodsight-${key}-${new Date().toISOString().slice(0,10)}.json`;
  a.click();
  URL.revokeObjectURL(url);
  showDEMToast('JSON exported!','','');
}

